// ── Stage 20: IPC cap-transfer / reply-cap / transfer-envelope lifetime ───────

#[test]
fn stage20_transfer_cap_materialize_success_sets_cap_refcount_to_two() {
    // Invariant 3/10: a successful transfer materialization (envelope take + grant
    // into the receiver cnode) leaves the MemoryObject with cap_refcount == 2
    // (sender's original cap + receiver's delegated cap) and consumes the envelope.
    let mut state = Bootstrap::init().expect("init");
    state.register_task(1).expect("task1");
    let (mo_id, mem_cap) = state.alloc_anonymous_memory_object().expect("mem");
    let (_eid, send_cap, _recv_cap) = state.create_endpoint(1).expect("endpoint");
    let endpoint = state
        .current_task_capability(send_cap)
        .expect("send cap")
        .object;

    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    assert_eq!(
        state.memory.memory_objects[slot].expect("obj").cap_refcount,
        1,
        "cap_refcount must be 1 after alloc (sender only)"
    );

    let handle = state
        .stash_transfer_envelope(ThreadId(0), mem_cap, endpoint, Some(ThreadId(1)), None)
        .expect("stash");
    // Take the envelope (recv side) then grant into the receiver's cnode, mirroring
    // materialize_received_transfer_cap.
    let envelope = state
        .take_transfer_envelope(handle, endpoint, ThreadId(1))
        .expect("take");
    let source = state
        .resolve_capability_for_task(envelope.source_tid.0, envelope.source_cap)
        .expect("source cap");
    let derived = state
        .grant_capability_task_to_task_with_rights(
            envelope.source_tid.0,
            envelope.source_cap,
            1,
            source.rights(),
        )
        .expect("grant");

    let slot = state.memory_object_slot_by_id(mo_id).expect("slot after");
    assert_eq!(
        state.memory.memory_objects[slot].expect("obj").cap_refcount,
        2,
        "cap_refcount must be 2 after transfer materialization"
    );
    // Envelope is consumed: a second take returns None.
    assert!(
        state
            .take_transfer_envelope(handle, endpoint, ThreadId(1))
            .is_none(),
        "envelope must be consumed exactly once"
    );
    // The materialized cap is a fresh slot in the receiver cnode.
    assert!(
        state.task_capability(1, derived).is_some(),
        "receiver must own materialized cap"
    );
}

#[test]
fn stage20_rollback_materialized_transfer_cap_restores_cap_refcount() {
    // Invariant 3/4/12: rolling back a materialized transfer cap removes the cnode
    // slot AND decrements cap_refcount back to the pre-materialization value.
    let mut state = Bootstrap::init().expect("init");
    state.register_task(1).expect("task1");
    let (mo_id, mem_cap) = state.alloc_anonymous_memory_object().expect("mem");

    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    let before = state.memory.memory_objects[slot].expect("obj").cap_refcount;
    assert_eq!(before, 1);

    let derived = state
        .grant_capability_task_to_task_with_rights(0, mem_cap, 1, CapRights::READ | CapRights::MAP)
        .expect("grant");
    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    assert_eq!(
        state.memory.memory_objects[slot].expect("obj").cap_refcount,
        2,
        "cap_refcount must be 2 after grant"
    );

    // Roll back as the recv-delivery copy-failure path would.
    let rolled = state.rollback_materialized_recv_cap(1, derived, false);
    assert!(rolled, "transfer-cap rollback must clear a slot");

    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    assert_eq!(
        state.memory.memory_objects[slot].expect("obj").cap_refcount,
        before,
        "rollback must restore cap_refcount to pre-grant value"
    );
    assert!(
        state.task_capability(1, derived).is_none(),
        "rolled-back cap must no longer exist in receiver cnode"
    );
}

#[test]
fn stage20_rollback_materialized_transfer_cap_double_call_is_harmless() {
    // Invariant 12: double rollback (slot already cleared) must not underflow and
    // must report no-op without panicking.
    let mut state = Bootstrap::init().expect("init");
    state.register_task(1).expect("task1");
    let (mo_id, mem_cap) = state.alloc_anonymous_memory_object().expect("mem");
    let derived = state
        .grant_capability_task_to_task_with_rights(0, mem_cap, 1, CapRights::READ | CapRights::MAP)
        .expect("grant");

    assert!(state.rollback_materialized_recv_cap(1, derived, false));
    // Second rollback: slot already gone (and the MemoryObject may be reclaimed).
    let second = state.rollback_materialized_recv_cap(1, derived, false);
    assert!(!second, "second rollback must be a no-op");
    // Source cap still intact, refcount must not be underflowed below 1.
    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    assert_eq!(
        state.memory.memory_objects[slot].expect("obj").cap_refcount,
        1,
        "source cap_refcount must remain 1 after double rollback"
    );
}

#[test]
fn stage20_rollback_materialized_reply_cap_clears_slot_and_waiter_id() {
    // Invariant 2/6: rolling back a materialized Reply cap fast-revokes the receiver
    // cnode slot and clears the global waiter_cap_id, while the ReplyCapRecord stays
    // live (the reply was never consumed by the mint).
    std::thread::Builder::new()
        .name("stage20_rollback_reply_cap".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            let (_eid, _send_cap, recv_cap) = state.create_endpoint(4).expect("endpoint");
            // create_reply_cap_for_caller mints the Reply cap into the caller's
            // (current task 0) cnode and reserves global slot 0.
            let reply_cap = state
                .create_reply_cap_for_caller(ThreadId(0), recv_cap, None)
                .expect("create reply cap");
            // The reserved global record is at index 0 for a fresh kernel.
            let reply_index = 0usize;
            assert!(state.reply_cap_record_present(reply_index));

            // Simulate materialization: record the caller-local cap as the waiter cap
            // (set_reply_cap_waiter_cap is what the recv path calls).
            let reply_gen = state.with_ipc_state(|ipc| ipc.reply_cap_generations[reply_index]);
            state.set_reply_cap_waiter_cap(reply_index, reply_gen, reply_cap);
            assert_eq!(
                state.reply_cap_record_waiter_cap(reply_index),
                Some(reply_cap),
                "waiter_cap_id must be set after materialization"
            );

            // Roll back as a recv-delivery copy failure would.
            let rolled = state.rollback_materialized_recv_cap(0, reply_cap, true);
            assert!(rolled, "reply-cap rollback must clear the cnode slot");
            assert_eq!(
                state.reply_cap_record_waiter_cap(reply_index),
                None,
                "waiter_cap_id must be cleared after rollback"
            );
            assert!(
                state.reply_cap_record_present(reply_index),
                "ReplyCapRecord must remain live (reply not consumed by mint)"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage20_reply_cap_double_revoke_is_idempotent() {
    // Invariant 2/12: ipc_reply revokes the one-shot reply cap; a second ipc_reply
    // returns a stable error (InvalidCapability) without panic or underflow.
    std::thread::Builder::new()
        .name("stage20_reply_cap_double_revoke".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            let (_eid, _send_cap, recv_cap) = state.create_endpoint(4).expect("endpoint");
            let reply_cap = state
                .create_reply_cap_for_caller(ThreadId(0), recv_cap, None)
                .expect("create reply cap");
            let reply = Message::new(7, b"ok").expect("reply");
            state.ipc_reply(reply_cap, reply).expect("first reply");
            // Drain the delivered reply so the endpoint state is clean.
            let _ = state.ipc_recv(recv_cap).expect("recv");
            // Global record must be consumed.
            assert!(
                !state.reply_cap_record_present(0),
                "ReplyCapRecord must be consumed after ipc_reply"
            );
            let replay = Message::new(7, b"no").expect("replay");
            assert_eq!(
                state.ipc_reply(reply_cap, replay),
                Err(KernelError::InvalidCapability),
                "second ipc_reply on a consumed reply cap must be a stable error"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage20_clear_reply_cap_waiter_cap_generation_guard() {
    // Invariant 2: clear_reply_cap_waiter_cap is generation-guarded — a stale
    // generation must not disturb a reused record.
    std::thread::Builder::new()
        .name("stage20_clear_waiter_cap_gen_guard".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            let (_eid, _send_cap, recv_cap) = state.create_endpoint(4).expect("endpoint");
            let reply_cap = state
                .create_reply_cap_for_caller(ThreadId(0), recv_cap, None)
                .expect("create reply cap");
            let reply_index = 0usize;
            let reply_gen = state.with_ipc_state(|ipc| ipc.reply_cap_generations[reply_index]);
            state.set_reply_cap_waiter_cap(reply_index, reply_gen, reply_cap);
            assert_eq!(
                state.reply_cap_record_waiter_cap(reply_index),
                Some(reply_cap)
            );

            // A clear with a stale generation must be ignored.
            state.clear_reply_cap_waiter_cap(reply_index, reply_gen.wrapping_sub(1));
            assert_eq!(
                state.reply_cap_record_waiter_cap(reply_index),
                Some(reply_cap),
                "stale-generation clear must be ignored"
            );
            // A clear with the correct generation succeeds.
            state.clear_reply_cap_waiter_cap(reply_index, reply_gen);
            assert_eq!(state.reply_cap_record_waiter_cap(reply_index), None);
        })
        .expect("spawn")
        .join()
        .expect("join");
}

// ── Stage 24 Part B: endpoint / reply-cap revoke + cnode-teardown audit ─────

#[test]
fn stage24_cnode_teardown_with_endpoint_cap_does_not_leave_receiver_waiter() {
    // A task blocked as an endpoint receiver must not be left as a stranded
    // endpoint_waiter after mark_task_dead.  clear_ipc_waiters_for_tid (called by
    // mark_task_dead) clears the receiver waiter slot for the dying tid.
    std::thread::Builder::new()
        .name("stage24_ep_recv_waiter_teardown".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            state.register_task(1).expect("task1");
            let (endpoint_idx, _send_cap, _recv_cap) = state.create_endpoint(4).expect("endpoint");

            // Inject task 1 as the endpoint receiver waiter.
            state.with_ipc_state_mut(|ipc| {
                ipc.endpoint_waiters[endpoint_idx] = Some(ThreadId(1));
            });
            assert_eq!(
                state.endpoint_waiter_count(endpoint_idx),
                1,
                "precondition: task 1 is the endpoint receiver waiter"
            );

            state.mark_task_dead(1).expect("mark dead");

            assert_eq!(
                state.endpoint_waiter_count(endpoint_idx),
                0,
                "mark_task_dead must clear the dead task's endpoint receiver waiter"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage24_cnode_teardown_with_endpoint_cap_does_not_leave_sender_waiter() {
    // A task blocked as an endpoint sender must not be left as a stranded
    // sender waiter after mark_task_dead.
    std::thread::Builder::new()
        .name("stage24_ep_send_waiter_teardown".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            state.register_task(1).expect("task1");
            let (endpoint_idx, _send_cap, _recv_cap) = state.create_endpoint(4).expect("endpoint");

            let msg = Message::new(0, b"blocked-send").expect("msg");
            state.with_ipc_state_mut(|ipc| {
                ipc.endpoint_sender_waiters[endpoint_idx][0] = Some(SenderWaiter {
                    tid: ThreadId(1),
                    msg,
                });
            });
            assert_eq!(
                state.sender_waiter_count(endpoint_idx),
                1,
                "precondition: task 1 is queued as an endpoint sender waiter"
            );

            state.mark_task_dead(1).expect("mark dead");

            assert_eq!(
                state.sender_waiter_count(endpoint_idx),
                0,
                "mark_task_dead must clear the dead task's endpoint sender waiter"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage24_reply_cap_cnode_teardown_clears_global_record() {
    // mark_task_dead(caller) calls revoke_reply_caps_for_caller, which clears the
    // global ReplyCapRecord keyed on caller_tid.  After teardown the global slot
    // must be empty (no lingering record referencing a destroyed cnode).
    std::thread::Builder::new()
        .name("stage24_reply_cap_teardown".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            state.register_task(1).expect("caller task");
            let (_eid, _send_cap, recv_cap_global) = state.create_endpoint(4).expect("endpoint");
            let recv_cap = state
                .grant_capability_task_to_task(0, recv_cap_global, 1)
                .expect("grant recv to t1");
            let _reply_cap = state
                .create_reply_cap_for_caller(ThreadId(1), recv_cap, None)
                .expect("create reply cap");
            assert!(
                state.reply_cap_record_present(0),
                "precondition: global reply record present for caller tid 1"
            );

            state.mark_task_dead(1).expect("mark dead");

            assert!(
                !state.reply_cap_record_present(0),
                "mark_task_dead(caller) must clear the global reply record"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage24_stale_reply_cap_cannot_be_reused_after_cnode_teardown() {
    // After the caller is torn down, the Reply CapId held by the replier is stale:
    // the global record is gone, so ipc_reply must return a stable StaleCapability
    // error rather than delivering or panicking.
    std::thread::Builder::new()
        .name("stage24_stale_reply_cap".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            state.register_task(1).expect("caller task");
            let (_eid, _send_cap, recv_cap_global) = state.create_endpoint(4).expect("endpoint");
            let recv_cap = state
                .grant_capability_task_to_task(0, recv_cap_global, 1)
                .expect("grant recv to t1");
            // Reply cap minted into the current (task 0 = replier) cnode.
            let reply_cap = state
                .create_reply_cap_for_caller(ThreadId(1), recv_cap, None)
                .expect("create reply cap");

            // Caller (task 1) dies: global record cleared by revoke_reply_caps_for_caller.
            state.mark_task_dead(1).expect("mark dead");

            assert_eq!(
                state.ipc_reply(reply_cap, Message::new(0, b"stale").expect("msg")),
                Err(KernelError::StaleCapability),
                "stale reply cap after caller teardown must be a stable error"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage24_endpoint_cap_revoke_does_not_affect_unrelated_endpoint() {
    // Endpoint caps are multi-owner (send cap is delegated cross-process during
    // spawn).  Revoking a cap for one endpoint must clear only that cnode slot and
    // must NOT destroy the endpoint object, nor disturb a second, unrelated
    // endpoint.
    std::thread::Builder::new()
        .name("stage24_ep_revoke_isolation".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            let cnode = state.current_task_cnode().expect("task0 cnode");

            let (ep_a, _send_a, recv_a) = state.create_endpoint(4).expect("endpoint A");
            let (ep_b, _send_b, _recv_b) = state.create_endpoint(4).expect("endpoint B");
            assert_ne!(ep_a, ep_b, "two distinct endpoints");

            let gen_a_before = state.with_ipc_state(|ipc| ipc.endpoint_generations[ep_a]);
            let gen_b_before = state.with_ipc_state(|ipc| ipc.endpoint_generations[ep_b]);

            // Revoke one cap (the receive cap) of endpoint A.
            state
                .revoke_capability_in_cnode(cnode, recv_a)
                .expect("revoke recv cap A");

            // Endpoint A object must still exist (multi-owner: send cap still live),
            // and its generation must be unchanged (revoke does not destroy it).
            assert!(
                state.with_ipc_state(|ipc| ipc.endpoints[ep_a].is_some()),
                "endpoint A object must survive single-cap revoke (multi-owner)"
            );
            assert_eq!(
                state.with_ipc_state(|ipc| ipc.endpoint_generations[ep_a]),
                gen_a_before,
                "endpoint A generation must be unchanged by cap revoke"
            );

            // Endpoint B must be entirely unaffected.
            assert!(
                state.with_ipc_state(|ipc| ipc.endpoints[ep_b].is_some()),
                "unrelated endpoint B must remain present"
            );
            assert_eq!(
                state.with_ipc_state(|ipc| ipc.endpoint_generations[ep_b]),
                gen_b_before,
                "unrelated endpoint B generation must be unchanged"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

#[test]
fn stage20_transfer_envelope_double_take_is_harmless() {
    // Invariant 1/12: an envelope is consumed exactly once; a second take returns
    // None and does not double-decrement the pin_refcount.
    let mut state = Bootstrap::init().expect("init");
    let (mo_id, mem_cap) = state.alloc_anonymous_memory_object().expect("mem");
    let (_eid, send_cap, _recv_cap) = state.create_endpoint(1).expect("endpoint");
    let endpoint = state
        .current_task_capability(send_cap)
        .expect("send cap")
        .object;

    let handle = state
        .stash_transfer_envelope(
            ThreadId(0),
            mem_cap,
            endpoint,
            None,
            Some(TransferSharedRegion {
                offset: 0x2000,
                len: PAGE_SIZE as u64,
            }),
        )
        .expect("stash");
    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    assert_eq!(
        state.memory.memory_objects[slot].expect("obj").pin_refcount,
        1
    );

    assert!(
        state
            .take_transfer_envelope(handle, endpoint, ThreadId(0))
            .is_some()
    );
    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    assert_eq!(
        state.memory.memory_objects[slot].expect("obj").pin_refcount,
        0,
        "pin_refcount must drop to 0 after take"
    );
    // Second take is a no-op: returns None, pin_refcount stays 0 (no underflow).
    assert!(
        state
            .take_transfer_envelope(handle, endpoint, ThreadId(0))
            .is_none()
    );
    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    assert_eq!(
        state.memory.memory_objects[slot].expect("obj").pin_refcount,
        0,
        "double take must not underflow pin_refcount"
    );
}

#[test]
fn stage20_failed_transfer_send_cleans_envelope_and_keeps_refcount() {
    // Invariant 1/3: ipc_send_with_cap_transfer error-path takes back the envelope
    // (cleaned exactly once) and the source cap_refcount is unchanged (cap stays
    // with the sender; nothing was minted into a receiver).
    let mut state = Bootstrap::init().expect("init");
    state.register_task(1).expect("task1");
    let (mo_id, mem_cap) = state.alloc_anonymous_memory_object().expect("mem");
    let (_eid, send_cap, _recv_cap) = state.create_endpoint(1).expect("endpoint");
    let endpoint = state
        .current_task_capability(send_cap)
        .expect("send cap")
        .object;

    let before = {
        let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
        state.memory.memory_objects[slot].expect("obj").cap_refcount
    };

    // Directly model the stash + error cleanup contract: stash, then take back.
    let handle = state
        .stash_transfer_envelope(ThreadId(0), mem_cap, endpoint, Some(ThreadId(1)), None)
        .expect("stash");
    let t_created = state.ipc_path_telemetry().transfer_records_created;
    // Error path takes the envelope back with the bound receiver tid.
    assert!(
        state
            .take_transfer_envelope(handle, endpoint, ThreadId(1))
            .is_some(),
        "error cleanup must take the envelope exactly once"
    );
    let t_mat = state.ipc_path_telemetry().transfer_records_materialized;
    assert!(t_mat >= 1 && t_created >= 1);

    let after = {
        let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
        state.memory.memory_objects[slot].expect("obj").cap_refcount
    };
    assert_eq!(
        after, before,
        "failed transfer must not change source cap_refcount"
    );
}

#[test]
fn stage20_active_transfer_mapping_is_two_phase_and_refcount_safe() {
    // Invariant 11: active-transfer mappings register/remove cleanly and the
    // backing MemoryObject cap_refcount is governed only by cap mint/revoke, not by
    // mapping registration.
    let mut state = Bootstrap::init().expect("init");
    state.register_task(1).expect("task1");
    let (mo_id, mem_cap) = state.alloc_anonymous_memory_object().expect("mem");
    let derived = state
        .grant_capability_task_to_task_with_rights(0, mem_cap, 1, CapRights::READ | CapRights::MAP)
        .expect("grant");

    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    let refcount = state.memory.memory_objects[slot].expect("obj").cap_refcount;
    assert_eq!(refcount, 2);

    state
        .register_active_transfer_mapping(ThreadId(1), derived, VirtAddr(0x9000), PAGE_SIZE)
        .expect("register");
    // Registration must not change cap_refcount.
    let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
    assert_eq!(
        state.memory.memory_objects[slot].expect("obj").cap_refcount,
        2,
        "mapping registration must not touch cap_refcount"
    );
    assert!(
        state
            .active_transfer_mapping_for(ThreadId(1), derived)
            .is_some()
    );

    assert!(state.remove_active_transfer_mapping(ThreadId(1), derived));
    assert!(
        state
            .active_transfer_mapping_for(ThreadId(1), derived)
            .is_none(),
        "mapping must be removed exactly once"
    );
    // Removal of a non-existent mapping is a harmless false.
    assert!(!state.remove_active_transfer_mapping(ThreadId(1), derived));
}

#[test]
fn stage20_reply_cap_creation_does_not_change_memory_cap_refcount() {
    // Invariant 9/10: reply-cap creation mints a Reply object (no MemoryObject), so
    // no MemoryObject cap_refcount changes; recv-v2 reply-cap metadata is unaffected
    // by unrelated MemoryObject allocations.
    std::thread::Builder::new()
        .name("stage20_reply_cap_no_mem_refcount".into())
        .stack_size(8 * 1024 * 1024)
        .spawn(|| {
            let mut state = Bootstrap::init().expect("init");
            let (mo_id, _mem_cap) = state.alloc_anonymous_memory_object().expect("mem");
            let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
            let before = state.memory.memory_objects[slot].expect("obj").cap_refcount;

            let (_eid, _send_cap, recv_cap) = state.create_endpoint(4).expect("endpoint");
            let _reply_cap = state
                .create_reply_cap_for_caller(ThreadId(0), recv_cap, None)
                .expect("create reply cap");

            let slot = state.memory_object_slot_by_id(mo_id).expect("slot");
            let after = state.memory.memory_objects[slot].expect("obj").cap_refcount;
            assert_eq!(
                before, after,
                "reply-cap creation must not touch MemoryObject cap_refcount"
            );
        })
        .expect("spawn")
        .join()
        .expect("join");
}

// ── End Stage 16 timeout/deadline/block-state tests ───────────────────────────

// ── Stage 21: notification / IRQ-route lifetime tests ─────────────────────────

/// Set `tid` to `Blocked(EndpointReceive(0))` to model a task parked on a
/// notification recv, without driving the full block path. Mirrors the
/// injection idiom used by the Stage 16 waiter-cleanup tests.
#[cfg(test)]
fn stage21_block_on_notification(state: &mut KernelState, tid: u64) {
    state
        .with_tcbs_mut(|tcbs| {
            let tcb = tcbs
                .iter_mut()
                .flatten()
                .find(|t| t.tid.0 == tid)
                .expect("tcb");
            tcb.status = TaskStatus::Blocked(WaitReason::EndpointReceive(CapId(0)));
            Ok::<_, KernelError>(())
        })
        .expect("block");
}

#[test]
fn stage21_signal_wakes_waiting_task_exactly_once() {
    // route_external_irq -> signal_notification must wake a Blocked waiter once
    // (Blocked -> Runnable, waiter slot consumed). A second IRQ with no waiter
    // registered must not re-wake or re-enqueue anything.
    let mut state = Bootstrap::init().expect("init");
    state.register_task(2101).expect("task");
    let (notif_idx, notif_cap, _recv) = state.create_notification(4).expect("notif");
    state.bind_irq_notification(9, notif_cap).expect("bind");

    stage21_block_on_notification(&mut state, 2101);
    state.with_ipc_state_mut(|ipc| {
        ipc.notification_waiters[notif_idx] = Some(ThreadId(2101));
    });
    assert!(state.task_is_blocked(2101), "waiter blocked before signal");
    assert_eq!(
        state.notification_waiter_count(notif_idx),
        1,
        "waiter present"
    );

    state.route_external_irq(9).expect("irq");
    assert!(state.task_is_runnable(2101), "waiter woken to Runnable");
    assert_eq!(
        state.notification_waiter_count(notif_idx),
        0,
        "waiter slot consumed by signal"
    );

    // Second IRQ: no registered waiter, task already Runnable, must stay Runnable.
    state.route_external_irq(9).expect("irq2");
    assert!(state.task_is_runnable(2101), "no double-wake");
    assert_eq!(
        state.notification_waiter_count(notif_idx),
        0,
        "still no waiter"
    );
}

#[test]
fn stage21_signal_skips_dead_waiter_safely() {
    // A stale Dead-task TID lingering in notification_waiters must NOT be
    // resurrected to Runnable by a signal.
    let mut state = Bootstrap::init().expect("init");
    state.register_task(2102).expect("task");
    let (notif_idx, notif_cap, _recv) = state.create_notification(4).expect("notif");
    state.bind_irq_notification(10, notif_cap).expect("bind");

    state.mark_task_dead(2102).expect("dead");
    assert!(state.task_is_dead(2102), "dead before injection");
    // Simulate a stale waiter reference surviving (defence-in-depth).
    state.with_ipc_state_mut(|ipc| {
        ipc.notification_waiters[notif_idx] = Some(ThreadId(2102));
    });

    state.route_external_irq(10).expect("irq");
    assert!(
        state.task_is_dead(2102),
        "Dead task must not be resurrected by signal_notification"
    );
}

