// ===========================================================================
// Stage 134 — Kernel stack depth / stack_base audit
// ===========================================================================
#[cfg(test)]
mod stage134_kernel_stack_audit {
    use super::Bootstrap;

    const THREAD_STATE_SRC: &str = include_str!("thread_state.rs");
    const TRAP_RS_SRC: &str = include_str!("../../arch/x86_64/trap.rs");

    // Crash-site constants (from the observed Stage 133/134 fault).
    const OLD_KERNEL_STACK_REGION_SIZE: usize = 0x4000;
    const OBSERVED_FAULT_PAGE: usize = 0xffff_8000_0000_b000;
    const OBSERVED_RSP: usize = 0xffff_8000_0000_bfc0;
    const KERNEL_STACK_REGION_BASE: usize = 0xFFFF_8000_0000_0000;
    // tid=1 was at idx=3 in the TCB array (base = REGION_BASE + 3 * 0x4000 = 0xffff80000000c000).
    const TID1_IDX: usize = 3;

    // 1. Prove fault page 0xffff80000000b000 is below the old stack base for idx=3.
    #[test]
    fn stage134_fault_page_below_old_stack_base() {
        let old_base = KERNEL_STACK_REGION_BASE + TID1_IDX * OLD_KERNEL_STACK_REGION_SIZE;
        assert!(
            OBSERVED_FAULT_PAGE < old_base,
            "fault page 0x{:x} must be below old stack base 0x{:x} — confirms overflow",
            OBSERVED_FAULT_PAGE,
            old_base
        );
    }

    // 2. New KERNEL_STACK_REGION_SIZE must be larger than the old 16 KB.
    #[test]
    fn stage134_region_size_increased_beyond_16kb() {
        assert!(
            THREAD_STATE_SRC.contains("KERNEL_STACK_REGION_SIZE: usize = 0x8000"),
            "KERNEL_STACK_REGION_SIZE must be increased to 0x8000 (32 KB) in thread_state.rs"
        );
    }

    // 3. KERNEL_STACK_GUARD_SIZE declared as at least one page.
    #[test]
    fn stage134_guard_size_constant_is_one_page() {
        assert!(
            THREAD_STATE_SRC.contains("KERNEL_STACK_GUARD_SIZE"),
            "thread_state.rs must declare KERNEL_STACK_GUARD_SIZE"
        );
        assert!(
            THREAD_STATE_SRC.contains("KERNEL_STACK_GUARD_SIZE: usize = 0x1000"),
            "KERNEL_STACK_GUARD_SIZE must equal one page (0x1000)"
        );
    }

    // 4. New actual stack size (REGION_SIZE - GUARD_SIZE) exceeds the observed
    //    overflow depth (old REGION_SIZE + bytes past old base).
    #[test]
    fn stage134_new_actual_stack_covers_observed_rsp() {
        let new_region_size: usize = 0x8000;
        let new_guard_size: usize = 0x1000;
        let new_actual_stack = new_region_size - new_guard_size;

        let old_base = KERNEL_STACK_REGION_BASE + TID1_IDX * OLD_KERNEL_STACK_REGION_SIZE;
        // RSP descended 0x40 bytes below old_base at time of crash.
        let overflow_depth = old_base - OBSERVED_RSP;
        let required_stack_size = OLD_KERNEL_STACK_REGION_SIZE + overflow_depth;

        assert!(
            new_actual_stack > required_stack_size,
            "new actual stack 0x{:x} must exceed required depth 0x{:x} (old_size=0x{:x} + overflow=0x{:x})",
            new_actual_stack,
            required_stack_size,
            OLD_KERNEL_STACK_REGION_SIZE,
            overflow_depth,
        );
    }

    // 5. provision_default_kernel_context computes region_base then adds guard.
    #[test]
    fn stage134_provision_skips_guard_page_for_stack_base() {
        assert!(
            THREAD_STATE_SRC.contains("region_base"),
            "provision_default_kernel_context must compute region_base separately from stack_base"
        );
        assert!(
            THREAD_STATE_SRC.contains("KERNEL_STACK_GUARD_SIZE"),
            "provision_default_kernel_context must add KERNEL_STACK_GUARD_SIZE to form stack_base"
        );
    }

    // 6. KERNEL_STACK_RANGE diagnostic emitted from thread_state.rs.
    #[test]
    fn stage134_kernel_stack_range_diagnostic_emitted() {
        assert!(
            THREAD_STATE_SRC.contains("KERNEL_STACK_RANGE"),
            "thread_state.rs must emit KERNEL_STACK_RANGE diagnostic"
        );
    }

    // 7. KERNEL_STACK_WATERMARK diagnostic emitted from trap.rs.
    #[test]
    fn stage134_kernel_stack_watermark_emitted_in_trap_rs() {
        assert!(
            TRAP_RS_SRC.contains("KERNEL_STACK_WATERMARK"),
            "trap.rs must emit KERNEL_STACK_WATERMARK diagnostic"
        );
    }

    // 8. KERNEL_STACK_OVERFLOW_DETECTED diagnostic emitted from trap.rs.
    #[test]
    fn stage134_kernel_stack_overflow_detected_emitted_in_trap_rs() {
        assert!(
            TRAP_RS_SRC.contains("KERNEL_STACK_OVERFLOW_DETECTED"),
            "trap.rs must emit KERNEL_STACK_OVERFLOW_DETECTED diagnostic"
        );
    }

    // 9. Functional: provision_default_kernel_context places stack_base one guard
    //    page above the region boundary and gives stack size = REGION_SIZE - GUARD.
    #[test]
    fn stage134_provisioned_stack_base_skips_guard_page() {
        let mut state = Bootstrap::init().expect("init");
        state.register_task(300).expect("register task 300");
        let ctx = state.thread_kernel_context(300).expect("context");
        let base = ctx.stack_base.expect("stack_base set").0 as usize;
        let top = ctx.stack_top.expect("stack_top set").0 as usize;

        let new_region_size: usize = 0x8000;
        let new_guard_size: usize = 0x1000;

        // base must be at guard_size offset within its region slot.
        assert_eq!(
            base % new_region_size,
            new_guard_size,
            "stack_base 0x{:x} must be offset from region start by guard_size 0x{:x}",
            base,
            new_guard_size
        );
        // Actual mapped stack = REGION_SIZE - GUARD_SIZE.
        assert_eq!(
            top - base,
            new_region_size - new_guard_size,
            "actual stack size 0x{:x} must equal region_size(0x{:x}) - guard_size(0x{:x})",
            top - base,
            new_region_size,
            new_guard_size
        );
    }
}

// ===========================================================================
// Stage 135 — Remove huge stack frame in ensure_pt_allocator_initialized
// ===========================================================================
#[cfg(test)]
mod stage135_pt_allocator_no_stack_scratch {
    use crate::kernel::syscall::{SYSCALL_COUNT, Syscall};

    const FRAME_ALLOC_SRC: &str = include_str!("../frame_allocator.rs");
    const THREAD_STATE_SRC: &str = include_str!("thread_state.rs");
    const BOOT_CMDLINE_SRC: &str = include_str!("../boot_command_line.rs");

    // 1. ensure_pt_allocator_initialized must not create a local PhysicalFrameAllocator.
    //    The old pattern `let mut allocator = PhysicalFrameAllocator::new_uninit()` inside
    //    ensure_pt_allocator_initialized caused a ~209 KB stack frame (subq $0x33140, %rsp).
    #[test]
    fn stage135_no_local_pfa_in_ensure_pt_initialized() {
        // The source must not contain the large-stack anti-pattern as a local variable
        // inside ensure_pt_allocator_initialized.  We detect this by checking that
        // the static initializer uses new_uninit() but the function body does not re-create one.
        let fn_start = FRAME_ALLOC_SRC
            .find("fn ensure_pt_allocator_initialized")
            .expect("ensure_pt_allocator_initialized must exist");
        // Find the closing brace of the function (next `}` on its own line after the fn).
        let fn_body_start = fn_start
            + FRAME_ALLOC_SRC[fn_start..]
                .find('{')
                .expect("opening brace");
        let fn_body = &FRAME_ALLOC_SRC[fn_body_start..];
        // The function body must not contain `PhysicalFrameAllocator::new_uninit()` as
        // a local binding — that is the large-stack anti-pattern we removed in Stage 135.
        assert!(
            !fn_body[..fn_body.find('}').unwrap_or(fn_body.len())]
                .contains("let mut allocator = PhysicalFrameAllocator::new_uninit()"),
            "ensure_pt_allocator_initialized must not create a local PhysicalFrameAllocator"
        );
    }

    // 2. PT_FRAME_ALLOCATOR static must hold PhysicalFrameAllocator directly (no Option).
    #[test]
    fn stage135_pt_frame_allocator_static_not_option() {
        assert!(
            FRAME_ALLOC_SRC.contains("SpinLockIrq<PhysicalFrameAllocator>"),
            "PT_FRAME_ALLOCATOR must be SpinLockIrq<PhysicalFrameAllocator> (not Option)"
        );
        assert!(
            !FRAME_ALLOC_SRC.contains("SpinLockIrq<Option<PhysicalFrameAllocator>>"),
            "PT_FRAME_ALLOCATOR must not wrap PhysicalFrameAllocator in Option after Stage 135"
        );
    }

    // 3. PT_ALLOCATOR_INIT_BEGIN marker must be present.
    #[test]
    fn stage135_pt_allocator_init_begin_marker() {
        assert!(
            FRAME_ALLOC_SRC.contains("PT_ALLOCATOR_INIT_BEGIN"),
            "frame_allocator.rs must emit PT_ALLOCATOR_INIT_BEGIN"
        );
    }

    // 4. PT_ALLOCATOR_INIT_NO_STACK_SCRATCH marker must be present.
    #[test]
    fn stage135_pt_allocator_init_no_stack_scratch_marker() {
        assert!(
            FRAME_ALLOC_SRC.contains("PT_ALLOCATOR_INIT_NO_STACK_SCRATCH"),
            "frame_allocator.rs must emit PT_ALLOCATOR_INIT_NO_STACK_SCRATCH"
        );
    }

    // 5. PT_ALLOCATOR_INIT_DONE marker must be present.
    #[test]
    fn stage135_pt_allocator_init_done_marker() {
        assert!(
            FRAME_ALLOC_SRC.contains("PT_ALLOCATOR_INIT_DONE"),
            "frame_allocator.rs must emit PT_ALLOCATOR_INIT_DONE"
        );
    }

    // 6. Stage 134 stack constants remain sane.
    #[test]
    fn stage135_stage134_constants_sane() {
        use crate::kernel::boot::thread_state::{
            KERNEL_STACK_GUARD_SIZE, KERNEL_STACK_REGION_SIZE,
        };
        assert_eq!(
            KERNEL_STACK_REGION_SIZE, 0x8000,
            "Stage 134 increased KERNEL_STACK_REGION_SIZE to 32 KB"
        );
        assert_eq!(
            KERNEL_STACK_GUARD_SIZE, 0x1000,
            "Stage 134 guard page must be exactly one page"
        );
        // Usable stack = REGION_SIZE - GUARD_SIZE must be at least 24 KB.
        assert!(
            KERNEL_STACK_REGION_SIZE - KERNEL_STACK_GUARD_SIZE >= 24 * 1024,
            "usable kernel stack must be at least 24 KB"
        );
        // Check that the thread_state source still carries the Stage 134 constants.
        assert!(
            THREAD_STATE_SRC.contains("KERNEL_STACK_REGION_SIZE"),
            "thread_state.rs must define KERNEL_STACK_REGION_SIZE"
        );
        assert!(
            THREAD_STATE_SRC.contains("KERNEL_STACK_GUARD_SIZE"),
            "thread_state.rs must define KERNEL_STACK_GUARD_SIZE"
        );
    }

    // 7. D6 switch-proof mode must remain default-off (gated by boot knob).
    #[test]
    fn stage135_d6_proof_default_off() {
        assert!(
            BOOT_CMDLINE_SRC.contains("d6_switch_proof: Option<bool>")
                && BOOT_CMDLINE_SRC.contains("set_d6_controlled_switch_proof_enabled"),
            "d6_switch_proof must be an Optional boot knob (default-off)"
        );
    }

    // 8. SYSCALL_COUNT must remain 31.
    #[test]
    fn stage135_syscall_count_unchanged() {
        assert_eq!(SYSCALL_COUNT, 31, "Stage 135 must not change SYSCALL_COUNT");
    }

    // 9. Syscall::VARIANT_COUNT must remain 23.
    #[test]
    fn stage135_syscall_variant_count_unchanged() {
        assert_eq!(
            Syscall::VARIANT_COUNT,
            23,
            "Stage 135 must not change Syscall::VARIANT_COUNT"
        );
    }
}

// ===========================================================================
// Stage 136 — Eliminate huge PhysicalFrameAllocator method stack frames
// ===========================================================================
#[cfg(test)]
mod stage136_pfa_no_method_stack_frames {
    use crate::kernel::syscall::{SYSCALL_COUNT, Syscall};

    const FRAME_ALLOC_SRC: &str = include_str!("../frame_allocator.rs");

    // 1. PhysicalFrameAllocator must not implement Copy.
    //    Find the #[derive(...)] immediately before `pub struct PhysicalFrameAllocator`
    //    and verify it does not include Copy.
    #[test]
    fn stage136_pfa_not_copy() {
        let pfa_pos = FRAME_ALLOC_SRC
            .find("pub struct PhysicalFrameAllocator")
            .expect("PhysicalFrameAllocator must be defined");
        let before_struct = &FRAME_ALLOC_SRC[..pfa_pos];
        let derive_start = before_struct
            .rfind("#[derive(")
            .expect("derive attr before PFA");
        let derive_end = FRAME_ALLOC_SRC[derive_start..]
            .find(']')
            .expect("closing ]");
        let derive_text = &FRAME_ALLOC_SRC[derive_start..derive_start + derive_end + 1];
        assert!(
            !derive_text.contains("Copy"),
            "PhysicalFrameAllocator derive must not include Copy after Stage 136: {derive_text}"
        );
    }

    // 2. No large rollback copy pattern: `let mut next = *self` must not appear.
    #[test]
    fn stage136_no_let_next_self_copy() {
        assert!(
            !FRAME_ALLOC_SRC.contains("let mut next = *self"),
            "frame_allocator.rs must not contain 'let mut next = *self' after Stage 136"
        );
        assert!(
            !FRAME_ALLOC_SRC.contains("let next = *self"),
            "frame_allocator.rs must not contain 'let next = *self' after Stage 136"
        );
    }

    // 3. No large frame_refs stack copy: `let old = self.frame_refs` must not appear.
    #[test]
    fn stage136_no_stack_frame_refs_copy() {
        assert!(
            !FRAME_ALLOC_SRC.contains("let old = self.frame_refs"),
            "compact_frame_refs must not copy frame_refs to a stack local after Stage 136"
        );
    }

    // 4. FREE_CONTIG_SCRATCH static must be present (proves .bss approach is in place).
    #[test]
    fn stage136_free_contig_scratch_present() {
        assert!(
            FRAME_ALLOC_SRC.contains("FREE_CONTIG_SCRATCH"),
            "frame_allocator.rs must define FREE_CONTIG_SCRATCH for free_contiguous"
        );
    }

    // 5. COMPACT_SCRATCH static must be present.
    #[test]
    fn stage136_compact_scratch_present() {
        assert!(
            FRAME_ALLOC_SRC.contains("COMPACT_SCRATCH"),
            "frame_allocator.rs must define COMPACT_SCRATCH for compact_frame_refs"
        );
    }

    // 6. pfa_clone_to helper must be present (stack-safe field-by-field copy).
    #[test]
    fn stage136_pfa_clone_to_helper_present() {
        assert!(
            FRAME_ALLOC_SRC.contains("fn pfa_clone_to"),
            "frame_allocator.rs must define pfa_clone_to for stack-safe PFA copying"
        );
        assert!(
            FRAME_ALLOC_SRC.contains("copy_from_slice"),
            "pfa_clone_to must use copy_from_slice to avoid stack temporaries"
        );
    }

    // 7. compact_frame_refs must be #[inline(never)].
    #[test]
    fn stage136_compact_frame_refs_not_inlined() {
        assert!(
            FRAME_ALLOC_SRC.contains("#[inline(never)]\n    fn compact_frame_refs"),
            "compact_frame_refs must be #[inline(never)] to prevent 192 KB frame inlining"
        );
    }

    // 8. Stage 135 markers must still be present.
    #[test]
    fn stage136_stage135_markers_preserved() {
        assert!(
            FRAME_ALLOC_SRC.contains("PT_ALLOCATOR_INIT_BEGIN"),
            "PT_ALLOCATOR_INIT_BEGIN marker from Stage 135 must remain"
        );
        assert!(
            FRAME_ALLOC_SRC.contains("PT_ALLOCATOR_INIT_NO_STACK_SCRATCH"),
            "PT_ALLOCATOR_INIT_NO_STACK_SCRATCH marker from Stage 135 must remain"
        );
        assert!(
            FRAME_ALLOC_SRC.contains("PT_ALLOCATOR_INIT_DONE"),
            "PT_ALLOCATOR_INIT_DONE marker from Stage 135 must remain"
        );
    }

    // 9. SYSCALL_COUNT must remain 31.
    #[test]
    fn stage136_syscall_count_unchanged() {
        assert_eq!(SYSCALL_COUNT, 31, "Stage 136 must not change SYSCALL_COUNT");
    }

    // 10. Syscall::VARIANT_COUNT must remain 23.
    #[test]
    fn stage136_syscall_variant_count_unchanged() {
        assert_eq!(
            Syscall::VARIANT_COUNT,
            23,
            "Stage 136 must not change Syscall::VARIANT_COUNT"
        );
    }
}

// ===========================================================================
// Stage 137 — diagnose/fix repeated tid=10000 user stack page fault loop
// ===========================================================================
#[cfg(test)]
mod stage137_demand_pf_loop_fix {
    use crate::kernel::syscall::{SYSCALL_COUNT, Syscall};

    const TRAP_SRC: &str = include_str!("../../arch/x86_64/trap.rs");
    const FAULT_SRC: &str = include_str!("fault_state.rs");

    // 1. PAGE_FAULT_RAW is emitted using the hardware interrupt-frame RIP
    //    (frame.saved_pc), not a stale task-context field.  The log must
    //    appear before set_current_cpu (before the first KernelState mutation)
    //    and must reference frame_rip from saved_pc.
    #[test]
    fn stage137_page_fault_raw_uses_frame_saved_pc() {
        assert!(
            TRAP_SRC.contains("PAGE_FAULT_RAW"),
            "trap.rs must emit PAGE_FAULT_RAW"
        );
        assert!(
            TRAP_SRC.contains("frame_rip=0x"),
            "PAGE_FAULT_RAW must include frame_rip field"
        );
        // The diagnostic block must precede set_current_cpu so it fires before
        // any KernelState mutation.
        let raw_pos = TRAP_SRC
            .find("PAGE_FAULT_RAW")
            .expect("PAGE_FAULT_RAW must be present");
        let set_cpu_pos = TRAP_SRC
            .find("kernel.set_current_cpu(cpu)")
            .expect("set_current_cpu must be present");
        assert!(
            raw_pos < set_cpu_pos,
            "PAGE_FAULT_RAW must be logged before kernel.set_current_cpu"
        );
        // Must pull saved_pc from the hardware frame, not from a task context.
        assert!(
            TRAP_SRC.contains("f.saved_pc"),
            "PAGE_FAULT_RAW must read frame_rip from f.saved_pc"
        );
    }

    // 2. x86_64 PF error-code bit decoding is covered: PAGE_FAULT_X86_ERROR
    //    must decode present (bit 0), write (bit 1), user (bit 2),
    //    reserved (bit 3) and instr (bit 4).
    #[test]
    fn stage137_x86_error_bits_decoded() {
        assert!(
            TRAP_SRC.contains("PAGE_FAULT_X86_ERROR"),
            "trap.rs must emit PAGE_FAULT_X86_ERROR"
        );
        assert!(
            TRAP_SRC.contains("present={}"),
            "PAGE_FAULT_X86_ERROR must include present field"
        );
        assert!(
            TRAP_SRC.contains("write={}"),
            "PAGE_FAULT_X86_ERROR must include write field"
        );
        assert!(
            TRAP_SRC.contains("user={}"),
            "PAGE_FAULT_X86_ERROR must include user field"
        );
        assert!(
            TRAP_SRC.contains("instr={}"),
            "PAGE_FAULT_X86_ERROR must include instr field"
        );
        assert!(
            TRAP_SRC.contains("reserved={}"),
            "PAGE_FAULT_X86_ERROR must include reserved field"
        );
    }

    // 3. PAGE_FAULT_HANDLED_DEMAND is only emitted after post-map PTE
    //    verification passes (pte_ok check).  The verify log must precede
    //    the handled log.
    #[test]
    fn stage137_handled_demand_requires_pte_verification() {
        assert!(
            FAULT_SRC.contains("PAGE_FAULT_DEMAND_VERIFY"),
            "fault_state.rs must emit PAGE_FAULT_DEMAND_VERIFY"
        );
        assert!(
            FAULT_SRC.contains("pte_ok"),
            "fault_state.rs must have a pte_ok gate before PAGE_FAULT_HANDLED_DEMAND"
        );
        // DEMAND_VERIFY must appear before HANDLED_DEMAND in source order.
        let verify_pos = FAULT_SRC
            .find("PAGE_FAULT_DEMAND_VERIFY")
            .expect("PAGE_FAULT_DEMAND_VERIFY must be present");
        let handled_pos = FAULT_SRC
            .find("PAGE_FAULT_HANDLED_DEMAND")
            .expect("PAGE_FAULT_HANDLED_DEMAND must be present");
        assert!(
            verify_pos < handled_pos,
            "PAGE_FAULT_DEMAND_VERIFY must precede PAGE_FAULT_HANDLED_DEMAND in source"
        );
        // PAGE_FAULT_HANDLED_DEMAND must be inside an `if pte_ok` guard.
        let after_verify = &FAULT_SRC[verify_pos..];
        let handled_rel = after_verify
            .find("PAGE_FAULT_HANDLED_DEMAND")
            .expect("HANDLED_DEMAND after VERIFY");
        let between = &after_verify[..handled_rel];
        assert!(
            between.contains("if pte_ok"),
            "PAGE_FAULT_HANDLED_DEMAND must be guarded by `if pte_ok`"
        );
    }

    // 4. Demand verification resolves the page in BOTH the task ASID and the
    //    active ASID (as tracked by hal.active_asid).
    #[test]
    fn stage137_demand_verify_checks_both_asids() {
        assert!(
            FAULT_SRC.contains("task_asid"),
            "fault_state.rs must resolve task_asid"
        );
        assert!(
            FAULT_SRC.contains("active_asid"),
            "fault_state.rs must resolve active_asid"
        );
        // Both resolve_page calls must appear in the demand-verify block.
        let verify_pos = FAULT_SRC
            .find("PAGE_FAULT_DEMAND_VERIFY")
            .expect("PAGE_FAULT_DEMAND_VERIFY must be present");
        let before_verify = &FAULT_SRC[..verify_pos];
        // Count occurrences of resolve_page in the region preceding DEMAND_VERIFY
        let resolve_count = before_verify.matches("resolve_page(task_asid").count()
            + before_verify.matches("resolve_page(active_asid").count();
        assert!(
            resolve_count >= 2,
            "Both task_asid and active_asid resolve_page calls must precede PAGE_FAULT_DEMAND_VERIFY"
        );
    }

    // 5. The user stack top page that contains the USER_STACK_RESOLVE probe
    //    (top-8 = 0x7ffb1ddfff8) also contains the faulting address
    //    (0x7ffb1ddffef9).  Both addresses fall in page 0x7ffb1ddff000.
    #[test]
    fn stage137_fault_addr_and_probe_share_stack_top_page() {
        const STACK_TOP: u64 = 0x7ffb1de00000;
        const PROBE: u64 = STACK_TOP - 8; // 0x7ffb1ddfff8
        const FAULT_ADDR: u64 = 0x7ffb1ddffef9;
        const PAGE_MASK: u64 = !0xFFF;

        let probe_page = PROBE & PAGE_MASK;
        let fault_page = FAULT_ADDR & PAGE_MASK;
        assert_eq!(
            probe_page, fault_page,
            "USER_STACK_RESOLVE probe and fault addr must be in the same page: probe_page=0x{probe_page:x} fault_page=0x{fault_page:x}"
        );
        assert_eq!(
            probe_page, 0x7ffb1ddff000,
            "top-of-stack page must be 0x7ffb1ddff000"
        );
    }

    // 6. SYSCALL_COUNT must remain 31.
    #[test]
    fn stage137_syscall_count_unchanged() {
        assert_eq!(SYSCALL_COUNT, 31, "Stage 137 must not change SYSCALL_COUNT");
    }

    // 7. Syscall::VARIANT_COUNT must remain 23.
    #[test]
    fn stage137_syscall_variant_count_unchanged() {
        assert_eq!(
            Syscall::VARIANT_COUNT,
            23,
            "Stage 137 must not change Syscall::VARIANT_COUNT"
        );
    }
}

// ── Stage 138 — x86_64 #PF trap-frame layout and hardware CR3 PTE state ──────
#[cfg(test)]
mod stage138_pf_frame_and_hw_pte_proof {
    use crate::kernel::syscall::{SYSCALL_COUNT, Syscall};

    #[cfg(target_arch = "x86_64")]
    const DTABLES_SRC: &str = include_str!("../../arch/x86_64/descriptor_tables.rs");
    #[cfg(target_arch = "x86_64")]
    const TRAP_SRC: &str = include_str!("../../arch/x86_64/trap.rs");
    const FAULT_SRC: &str = include_str!("fault_state.rs");

    // 1. x86_64 CPL3 #PF interrupt frame layout: interrupt_frame pointer points
    //    to RIP; error_code is at -8, then RIP/CS/RFLAGS/RSP/SS in order.
    //    Stage 138 decodes frame words as w0=error_code, w1=rip, …, w4=user_rsp.
    //    Verify that descriptor_tables.rs encodes this layout in the diagnostic.
    #[cfg(target_arch = "x86_64")]
    #[test]
    fn stage138_frame_decode_layout_in_source() {
        // emit_pf_frame_hw_diag must be present
        assert!(
            DTABLES_SRC.contains("emit_pf_frame_hw_diag"),
            "descriptor_tables.rs must define emit_pf_frame_hw_diag"
        );
        // error_code is at frame_ptr - 1 (i.e. -8 bytes from rip)
        assert!(
            DTABLES_SRC.contains("frame_ptr.sub(1)"),
            "error_code must be read as frame_ptr.sub(1) in emit_pf_frame_hw_diag"
        );
        // user_rsp is at frame_ptr + 3 (offset +24, the 4th CPU-pushed word)
        assert!(
            DTABLES_SRC.contains("frame_ptr.add(3)"),
            "user_rsp must be read as frame_ptr.add(3) in emit_pf_frame_hw_diag"
        );
        // PAGE_FAULT_FRAME_DECODE must be emitted
        assert!(
            DTABLES_SRC.contains("PAGE_FAULT_FRAME_DECODE"),
            "descriptor_tables.rs must emit PAGE_FAULT_FRAME_DECODE"
        );
        // PAGE_FAULT_FRAME_WORDS must be emitted
        assert!(
            DTABLES_SRC.contains("PAGE_FAULT_FRAME_WORDS"),
            "descriptor_tables.rs must emit PAGE_FAULT_FRAME_WORDS"
        );
    }

    // 2. PAGE_FAULT_RAW / PAGE_FAULT_FRAME_DECODE must use hardware-proven frame
    //    values (decoded from the interrupt frame memory), not from cached TrapFrame
    //    state.  The HW_REGS diagnostic must be emitted BEFORE build_trap_frame.
    #[cfg(target_arch = "x86_64")]
    #[test]
    fn stage138_hw_diag_emitted_before_build_trap_frame() {
        // emit_pf_frame_hw_diag must appear before build_trap_frame_from_saved_regs
        // in the dispatch function.
        let hw_diag_pos = DTABLES_SRC
            .find("emit_pf_frame_hw_diag(fault_addr")
            .expect("emit_pf_frame_hw_diag call site must be present");
        let build_frame_pos = DTABLES_SRC
            .find("build_trap_frame_from_saved_regs(regs")
            .expect("build_trap_frame_from_saved_regs call site must be present");
        assert!(
            hw_diag_pos < build_frame_pos,
            "emit_pf_frame_hw_diag must be called before build_trap_frame_from_saved_regs: hw_diag@{hw_diag_pos} build_frame@{build_frame_pos}"
        );
        // PAGE_FAULT_HW_REGS must be emitted by the diagnostic
        assert!(
            DTABLES_SRC.contains("PAGE_FAULT_HW_REGS"),
            "descriptor_tables.rs must emit PAGE_FAULT_HW_REGS"
        );
    }

    // 3. PAGE_FAULT_HANDLED_DEMAND must be guarded by both pte_ok (software) and
    //    hw_demand_ok (hardware CR3 walk success) — not just software resolve.
    #[test]
    fn stage138_handled_demand_requires_hw_walk_ok() {
        let handled_pos = FAULT_SRC
            .find("PAGE_FAULT_HANDLED_DEMAND")
            .expect("PAGE_FAULT_HANDLED_DEMAND must be present in fault_state.rs");
        // Find the nearest preceding if-guard
        let before_handled = &FAULT_SRC[..handled_pos];
        // The guard must mention hw_demand_ok
        assert!(
            before_handled.contains("hw_demand_ok"),
            "PAGE_FAULT_HANDLED_DEMAND must be inside an `if … hw_demand_ok` guard"
        );
        // Verify PAGE_FAULT_POST_DEMAND_HW_PTE_WALK precedes HANDLED_DEMAND
        let post_walk_pos = FAULT_SRC
            .find("PAGE_FAULT_POST_DEMAND_HW_PTE_WALK")
            .expect("PAGE_FAULT_POST_DEMAND_HW_PTE_WALK must be present in fault_state.rs");
        assert!(
            post_walk_pos < handled_pos,
            "PAGE_FAULT_POST_DEMAND_HW_PTE_WALK must precede PAGE_FAULT_HANDLED_DEMAND in source"
        );
    }

    // 4. Hardware CR3 compare marker must be present in trap.rs.
    #[cfg(target_arch = "x86_64")]
    #[test]
    fn stage138_hw_cr3_compare_marker_exists() {
        assert!(
            TRAP_SRC.contains("PAGE_FAULT_CR3_COMPARE"),
            "trap.rs must emit PAGE_FAULT_CR3_COMPARE"
        );
        // Must compare hw_cr3, active_cr3, and task_cr3
        assert!(
            TRAP_SRC.contains("hw_cr3"),
            "PAGE_FAULT_CR3_COMPARE block must read hw_cr3 via inline asm"
        );
        assert!(
            TRAP_SRC.contains("task_cr3"),
            "PAGE_FAULT_CR3_COMPARE block must resolve task_cr3"
        );
        assert!(
            TRAP_SRC.contains("active_cr3"),
            "PAGE_FAULT_CR3_COMPARE block must resolve active_cr3"
        );
    }

    // 5. Hardware PTE walk markers must exist in descriptor_tables.rs for both
    //    the CR2 page and the RIP page.
    #[cfg(target_arch = "x86_64")]
    #[test]
    fn stage138_hw_pte_walk_markers_exist() {
        // There must be at least two PAGE_FAULT_HW_PTE_WALK emissions (CR2 + RIP).
        let count = DTABLES_SRC.matches("PAGE_FAULT_HW_PTE_WALK").count();
        assert!(
            count >= 2,
            "descriptor_tables.rs must emit PAGE_FAULT_HW_PTE_WALK at least twice (CR2 page and RIP page), found {count}"
        );
        // hw_pte_walk_verbose must be called in the diagnostic function
        assert!(
            DTABLES_SRC.contains("hw_pte_walk_verbose"),
            "descriptor_tables.rs must call hw_pte_walk_verbose"
        );
        // The post-demand walk must be in fault_state.rs
        assert!(
            FAULT_SRC.contains("PAGE_FAULT_POST_DEMAND_HW_PTE_WALK"),
            "fault_state.rs must emit PAGE_FAULT_POST_DEMAND_HW_PTE_WALK"
        );
    }

    // 6. SYSCALL_COUNT must remain 31.
    #[test]
    fn stage138_syscall_count_unchanged() {
        assert_eq!(SYSCALL_COUNT, 31, "Stage 138 must not change SYSCALL_COUNT");
    }

    // 7. Syscall::VARIANT_COUNT must remain 23.
    #[test]
    fn stage138_syscall_variant_count_unchanged() {
        assert_eq!(
            Syscall::VARIANT_COUNT,
            23,
            "Stage 138 must not change Syscall::VARIANT_COUNT"
        );
    }
}

// ── Stage 139 — D6_SWITCH_PROOF hardware CR3 restore after proof cleanup ──────
#[cfg(test)]
mod stage139_d6_proof_cr3_cleanup {
    use crate::kernel::syscall::{SYSCALL_COUNT, Syscall};

    const EXEC_STATE_SRC: &str = include_str!("exec_state.rs");
    const THREAD_STATE_SRC: &str = include_str!("thread_state.rs");
    const TRAP_ENTRY_SRC: &str = include_str!("../../arch/trap_entry.rs");

    // 1. D6_PROOF_CR3_BEFORE marker must be emitted before the proof switch in
    //    exec_state.rs, inside maybe_run_d6_controlled_switch_proof.
    #[test]
    fn stage139_proof_cr3_before_marker_in_exec_state() {
        assert!(
            EXEC_STATE_SRC.contains("D6_PROOF_CR3_BEFORE"),
            "exec_state.rs must emit D6_PROOF_CR3_BEFORE before the proof switch"
        );
        // Must appear before maybe_switch_kernel_context in the proof function.
        let before_pos = EXEC_STATE_SRC
            .find("D6_PROOF_CR3_BEFORE")
            .expect("D6_PROOF_CR3_BEFORE must be present");
        let switch_pos = EXEC_STATE_SRC
            .find("maybe_switch_kernel_context(Some(outgoing_tid)")
            .expect("maybe_switch_kernel_context(Some(outgoing_tid)) call must be present");
        assert!(
            before_pos < switch_pos,
            "D6_PROOF_CR3_BEFORE must appear before maybe_switch_kernel_context: before@{before_pos} switch@{switch_pos}"
        );
    }

    // 2. D6_PROOF_CR3_AFTER_FIRST_RESUME marker must be emitted from the first-resume
    //    trampoline in thread_state.rs after post_switch_restore returns.
    #[test]
    fn stage139_proof_cr3_after_first_resume_in_thread_state() {
        assert!(
            THREAD_STATE_SRC.contains("D6_PROOF_CR3_AFTER_FIRST_RESUME"),
            "thread_state.rs trampoline must emit D6_PROOF_CR3_AFTER_FIRST_RESUME"
        );
        // Must appear after D6_FIRST_RESUME_POST_SWITCH_RESTORE_DONE.
        let restore_done_pos = THREAD_STATE_SRC
            .find("D6_FIRST_RESUME_POST_SWITCH_RESTORE_DONE")
            .expect("D6_FIRST_RESUME_POST_SWITCH_RESTORE_DONE must be present");
        let after_pos = THREAD_STATE_SRC
            .find("D6_PROOF_CR3_AFTER_FIRST_RESUME")
            .expect("D6_PROOF_CR3_AFTER_FIRST_RESUME must be present");
        assert!(
            restore_done_pos < after_pos,
            "D6_PROOF_CR3_AFTER_FIRST_RESUME must come after D6_FIRST_RESUME_POST_SWITCH_RESTORE_DONE"
        );
    }

    // 3. D6_PROOF_CR3_AFTER_SWITCH_BACK marker must be emitted at POINT 2 in
    //    trap_entry.rs after switch_frames returns.
    #[test]
    fn stage139_proof_cr3_after_switch_back_in_trap_entry() {
        assert!(
            TRAP_ENTRY_SRC.contains("D6_PROOF_CR3_AFTER_SWITCH_BACK"),
            "trap_entry.rs must emit D6_PROOF_CR3_AFTER_SWITCH_BACK at POINT 2"
        );
        // Must appear after D6_SWITCH_FRAMES_RETURNED_UNLOCKED.
        let returned_pos = TRAP_ENTRY_SRC
            .find("D6_SWITCH_FRAMES_RETURNED_UNLOCKED")
            .expect("D6_SWITCH_FRAMES_RETURNED_UNLOCKED must be present");
        let after_pos = TRAP_ENTRY_SRC
            .find("D6_PROOF_CR3_AFTER_SWITCH_BACK")
            .expect("D6_PROOF_CR3_AFTER_SWITCH_BACK must be present");
        assert!(
            returned_pos < after_pos,
            "D6_PROOF_CR3_AFTER_SWITCH_BACK must come after D6_SWITCH_FRAMES_RETURNED_UNLOCKED"
        );
    }

    // 4. D6_PROOF_CR3_CLEANUP_RESTORE marker must be emitted inside
    //    d6_emit_proof_cleanup_arch_markers in exec_state.rs.
    #[test]
    fn stage139_proof_cr3_cleanup_restore_in_exec_state() {
        assert!(
            EXEC_STATE_SRC.contains("D6_PROOF_CR3_CLEANUP_RESTORE"),
            "exec_state.rs d6_emit_proof_cleanup_arch_markers must emit D6_PROOF_CR3_CLEANUP_RESTORE"
        );
    }

    // 5. D6_PROOF_CR3_CLEANUP_OK marker must be emitted after the restore.
    #[test]
    fn stage139_proof_cr3_cleanup_ok_in_exec_state() {
        assert!(
            EXEC_STATE_SRC.contains("D6_PROOF_CR3_CLEANUP_OK"),
            "exec_state.rs d6_emit_proof_cleanup_arch_markers must emit D6_PROOF_CR3_CLEANUP_OK"
        );
        // RESTORE must precede OK.
        let restore_pos = EXEC_STATE_SRC
            .find("D6_PROOF_CR3_CLEANUP_RESTORE")
            .expect("D6_PROOF_CR3_CLEANUP_RESTORE must be present");
        let ok_pos = EXEC_STATE_SRC
            .find("D6_PROOF_CR3_CLEANUP_OK")
            .expect("D6_PROOF_CR3_CLEANUP_OK must be present");
        assert!(
            restore_pos < ok_pos,
            "D6_PROOF_CR3_CLEANUP_RESTORE must precede D6_PROOF_CR3_CLEANUP_OK"
        );
    }

    // 6. The CR3 restore must call switch_address_space in the cleanup function
    //    so that both the hardware CR3 and the HAL active_asid are updated.
    #[test]
    fn stage139_cleanup_restore_calls_switch_address_space() {
        // Find d6_emit_proof_cleanup_arch_markers function body.
        let fn_start = EXEC_STATE_SRC
            .find("fn d6_emit_proof_cleanup_arch_markers")
            .expect("d6_emit_proof_cleanup_arch_markers must be present");
        let fn_body = &EXEC_STATE_SRC[fn_start..];
        assert!(
            fn_body.contains("switch_address_space"),
            "d6_emit_proof_cleanup_arch_markers must call switch_address_space to restore hardware CR3"
        );
        assert!(
            fn_body.contains("D6_PROOF_CR3_CLEANUP_RESTORE"),
            "d6_emit_proof_cleanup_arch_markers must emit D6_PROOF_CR3_CLEANUP_RESTORE"
        );
    }

    // 7. SYSCALL_COUNT and Syscall::VARIANT_COUNT must remain unchanged.
    #[test]
    fn stage139_syscall_count_unchanged() {
        assert_eq!(SYSCALL_COUNT, 31, "Stage 139 must not change SYSCALL_COUNT");
        assert_eq!(
            Syscall::VARIANT_COUNT,
            23,
            "Stage 139 must not change Syscall::VARIANT_COUNT"
        );
    }
}

// ── Stage 140 — enforce hw CR3 == task_cr3 before every x86_64 ring-3 return ─
#[cfg(test)]
mod stage140_user_return_cr3 {
    use crate::kernel::syscall::{SYSCALL_COUNT, Syscall};

    const TRAP_RS_SRC: &str = include_str!("../../arch/x86_64/trap.rs");
    const BOOT_RS_SRC: &str = include_str!("../../arch/x86_64/boot.rs");
    const PAGE_TABLE_SRC: &str = include_str!("../../arch/x86_64/page_table.rs");
    const EXEC_STATE_SRC: &str = include_str!("exec_state.rs");
    const FAULT_SRC: &str = include_str!("fault_state.rs");

    // 1. The x86_64 return-from-trap path (restore_arch_thread_state) must call
    //    ensure_user_return_cr3 before the assembly stub does IRET.
    #[test]
    fn stage140_restore_arch_calls_ensure_user_return_cr3() {
        let fn_start = TRAP_RS_SRC
            .find("fn restore_arch_thread_state")
            .expect("restore_arch_thread_state must be present in trap.rs");
        let fn_body = &TRAP_RS_SRC[fn_start..];
        assert!(
            fn_body.contains("ensure_user_return_cr3"),
            "restore_arch_thread_state must call ensure_user_return_cr3 before returning"
        );
    }

    // 1b. The initial-dispatch path (enter_dispatched_user_task_if_available in
    //     boot.rs) must also call ensure_user_return_cr3 before enter_user_mode_iret.
    #[test]
    fn stage140_enter_dispatched_calls_ensure_user_return_cr3() {
        let fn_start = BOOT_RS_SRC
            .find("fn enter_dispatched_user_task_if_available")
            .expect("enter_dispatched_user_task_if_available must be present in boot.rs");
        let fn_body = &BOOT_RS_SRC[fn_start..];
        assert!(
            fn_body.contains("ensure_user_return_cr3"),
            "enter_dispatched_user_task_if_available must call ensure_user_return_cr3 before IRET"
        );
        // ensure_user_return_cr3 must appear before enter_user_mode_iret in source order.
        let ensure_pos = fn_body
            .find("ensure_user_return_cr3")
            .expect("ensure_user_return_cr3 in enter_dispatched");
        let iret_pos = fn_body
            .find("enter_user_mode_iret")
            .expect("enter_user_mode_iret in enter_dispatched");
        assert!(
            ensure_pos < iret_pos,
            "ensure_user_return_cr3 must precede enter_user_mode_iret in boot.rs"
        );
    }

    // 2. ensure_user_return_cr3 must read hardware CR3 and compare it to task_cr3.
    #[test]
    fn stage140_ensure_compares_hw_cr3_to_task_cr3() {
        let fn_start = TRAP_RS_SRC
            .find("fn ensure_user_return_cr3")
            .expect("ensure_user_return_cr3 must be defined in trap.rs");
        let fn_body = &TRAP_RS_SRC[fn_start..];
        assert!(
            fn_body.contains("read_hw_cr3"),
            "ensure_user_return_cr3 must call read_hw_cr3() to read the hardware CR3"
        );
        assert!(
            fn_body.contains("task_cr3"),
            "ensure_user_return_cr3 must compute task_cr3 from cr3_for_asid"
        );
        assert!(
            fn_body.contains("hw_cr3 != task_cr3"),
            "ensure_user_return_cr3 must compare hw_cr3 against task_cr3"
        );
    }

    // 3. The mismatch path must force-write CR3 via write_cr3_for_asid (bypassing
    //    HAL active_asid short-circuit), not via switch_address_space.
    #[test]
    fn stage140_mismatch_uses_write_cr3_for_asid_not_hal() {
        let fn_start = TRAP_RS_SRC
            .find("fn ensure_user_return_cr3")
            .expect("ensure_user_return_cr3 must be defined in trap.rs");
        let fn_body = &TRAP_RS_SRC[fn_start..];
        assert!(
            fn_body.contains("write_cr3_for_asid"),
            "mismatch path must call write_cr3_for_asid to force-write CR3"
        );
        // write_cr3_for_asid must exist in page_table.rs and bypass activate_asid.
        assert!(
            PAGE_TABLE_SRC.contains("fn write_cr3_for_asid"),
            "write_cr3_for_asid must be defined in page_table.rs"
        );
        assert!(
            !PAGE_TABLE_SRC
                .find("fn write_cr3_for_asid")
                .map(|p| PAGE_TABLE_SRC[p..].contains("activate_asid"))
                .unwrap_or(false),
            "write_cr3_for_asid must NOT call activate_asid (that has the RSP/RIP safety check)"
        );
    }

    // 4. All three diagnostic markers must exist in trap.rs.
    #[test]
    fn stage140_diagnostic_markers_exist() {
        assert!(
            TRAP_RS_SRC.contains("USER_CR3_PRE_IRET_CHECK"),
            "trap.rs must contain USER_CR3_PRE_IRET_CHECK marker"
        );
        assert!(
            TRAP_RS_SRC.contains("USER_CR3_PRE_IRET_SWITCH"),
            "trap.rs must contain USER_CR3_PRE_IRET_SWITCH marker"
        );
        assert!(
            TRAP_RS_SRC.contains("USER_CR3_PRE_IRET_OK"),
            "trap.rs must contain USER_CR3_PRE_IRET_OK marker"
        );
        // CHECK must precede SWITCH must precede OK in source order.
        let check_pos = TRAP_RS_SRC
            .find("USER_CR3_PRE_IRET_CHECK")
            .expect("CHECK present");
        let switch_pos = TRAP_RS_SRC
            .find("USER_CR3_PRE_IRET_SWITCH")
            .expect("SWITCH present");
        let ok_pos = TRAP_RS_SRC
            .find("USER_CR3_PRE_IRET_OK")
            .expect("OK present");
        assert!(
            check_pos < switch_pos,
            "CHECK must precede SWITCH in source"
        );
        assert!(switch_pos < ok_pos, "SWITCH must precede OK in source");
    }

    // 5. D6_PROOF_CR3_CLEANUP_OK from Stage 139 must remain present.
    #[test]
    fn stage140_d6_proof_cr3_cleanup_ok_still_present() {
        assert!(
            EXEC_STATE_SRC.contains("D6_PROOF_CR3_CLEANUP_OK"),
            "Stage 139 D6_PROOF_CR3_CLEANUP_OK must remain in exec_state.rs"
        );
    }

    // 6. PAGE_FAULT_HANDLED_DEMAND must still be gated on the hardware PTE walk.
    #[test]
    fn stage140_handled_demand_still_gated_on_hw_walk() {
        let handled_pos = FAULT_SRC
            .find("PAGE_FAULT_HANDLED_DEMAND")
            .expect("PAGE_FAULT_HANDLED_DEMAND must remain in fault_state.rs");
        let before = &FAULT_SRC[..handled_pos];
        assert!(
            before.contains("hw_demand_ok"),
            "PAGE_FAULT_HANDLED_DEMAND must remain inside an hw_demand_ok gate"
        );
    }

    // 7-8. Syscall ABI must not change.
    #[test]
    fn stage140_syscall_counts_unchanged() {
        assert_eq!(SYSCALL_COUNT, 31, "Stage 140 must not change SYSCALL_COUNT");
        assert_eq!(
            Syscall::VARIANT_COUNT,
            23,
            "Stage 140 must not change Syscall::VARIANT_COUNT"
        );
    }
}

// ── Stage 141 — repair kernel return context before CR3 force-write ──────────
#[cfg(test)]
mod stage141_kernel_return_ctx_repair {
    use crate::kernel::syscall::{SYSCALL_COUNT, Syscall};

    const TRAP_RS_SRC: &str = include_str!("../../arch/x86_64/trap.rs");
    const PAGE_TABLE_SRC: &str = include_str!("../../arch/x86_64/page_table.rs");
    const FAULT_SRC: &str = include_str!("fault_state.rs");

    // 1. ensure_user_return_cr3 must NOT bare-write CR3 before the return-context
    //    mapping helper runs: within the mismatch path, the call to
    //    ensure_kernel_return_context_mapped_for_asid must precede
    //    write_cr3_for_asid, and the force-write must be guarded by ctx_mapped.
    #[test]
    fn stage141_force_write_is_gated_on_return_ctx_mapping() {
        let fn_start = TRAP_RS_SRC
            .find("fn ensure_user_return_cr3")
            .expect("ensure_user_return_cr3 must be defined in trap.rs");
        let fn_body = &TRAP_RS_SRC[fn_start..];
        let map_pos = fn_body
            .find("ensure_kernel_return_context_mapped_for_asid")
            .expect("ensure_user_return_cr3 must call the return-context mapping helper");
        let write_pos = fn_body
            .find("write_cr3_for_asid")
            .expect("ensure_user_return_cr3 must still force-write CR3 on the safe path");
        assert!(
            map_pos < write_pos,
            "return-context mapping must precede write_cr3_for_asid in ensure_user_return_cr3"
        );
        // The force-write must be inside an `if ctx_mapped` guard.
        let guard_pos = fn_body
            .find("if ctx_mapped")
            .expect("write_cr3_for_asid must be guarded by `if ctx_mapped`");
        assert!(
            guard_pos < write_pos,
            "write_cr3_for_asid must be inside the `if ctx_mapped` guard"
        );
        // ensure_user_return_cr3 itself must not contain a raw `mov cr3` write;
        // the only CR3 write goes through the guarded write_cr3_for_asid helper.
        assert!(
            !fn_body[..write_pos].contains("mov cr3"),
            "ensure_user_return_cr3 must not bare-write CR3 with inline asm"
        );
    }

    // 2. The kernel-return mapping helper must map the RSP/stack pages
    //    supervisor-only writable (KERNEL_RW).  Stage 142 replaces the
    //    single-RSP-page approach with a full stack-window loop, so the
    //    "rsp" kind string is gone, but KERNEL_RW must still be present.
    #[test]
    fn stage141_rsp_page_mapped_supervisor_writable() {
        let fn_start = PAGE_TABLE_SRC
            .find("fn ensure_kernel_return_context_mapped_for_asid")
            .expect("ensure_kernel_return_context_mapped_for_asid must be defined");
        let fn_body = &PAGE_TABLE_SRC[fn_start..];
        assert!(
            fn_body.contains("PageFlags::KERNEL_RW"),
            "stack pages must be mapped with KERNEL_RW (supervisor-only writable)"
        );
        // Stage 142 uses a stack-window loop (USER_CR3_RETURN_STACK_MAP_BEGIN)
        // instead of the single-RSP-page call.  Either the old "rsp" kind or
        // the new stack-window marker must be present.
        assert!(
            fn_body.contains("USER_CR3_RETURN_STACK_MAP_BEGIN") || fn_body.contains("\"rsp\""),
            "either full stack-window mapping or rsp-page mapping must be present"
        );
        // The mapping primitive must reject user-accessible kernel pages.
        let helper_start = PAGE_TABLE_SRC
            .find("fn ensure_kernel_return_page_mapped")
            .expect("ensure_kernel_return_page_mapped must be defined");
        let helper_body = &PAGE_TABLE_SRC[helper_start..];
        assert!(
            helper_body.contains("!flags.user"),
            "ensure_kernel_return_page_mapped must assert the page is supervisor-only"
        );
    }

    // 3. The kernel-return mapping helper must map/prove the RIP page
    //    supervisor-only executable (user=false, execute=true).
    #[test]
    fn stage141_rip_page_mapped_supervisor_executable() {
        let fn_start = PAGE_TABLE_SRC
            .find("fn ensure_kernel_return_context_mapped_for_asid")
            .expect("ensure_kernel_return_context_mapped_for_asid must be defined");
        let fn_body = &PAGE_TABLE_SRC[fn_start..];
        let rip_pos = fn_body
            .find("\"rip\"")
            .expect("helper must distinguish the rip page kind");
        // Within the rip mapping call, flags must be supervisor-only executable.
        let around_rip = &fn_body[rip_pos.saturating_sub(200)..rip_pos.saturating_add(200)];
        assert!(
            around_rip.contains("execute: true"),
            "RIP page must be mapped executable"
        );
        assert!(
            around_rip.contains("user: false"),
            "RIP page must be mapped supervisor-only (user: false)"
        );
    }

    // 4. ASID_SWITCH_ABORT_DETAIL marker must exist in page_table.rs and must be
    //    emitted alongside (not instead of) ASID_SWITCH_ABORT.
    #[test]
    fn stage141_asid_switch_abort_detail_marker_exists() {
        assert!(
            PAGE_TABLE_SRC.contains("ASID_SWITCH_ABORT_DETAIL"),
            "page_table.rs must emit ASID_SWITCH_ABORT_DETAIL"
        );
        // ASID_SWITCH_ABORT must NOT be suppressed.
        assert!(
            PAGE_TABLE_SRC.contains("\"ASID_SWITCH_ABORT asid={} reason=kernel_mapping_missing\""),
            "ASID_SWITCH_ABORT must remain (improved with detail, not removed)"
        );
        let detail_pos = PAGE_TABLE_SRC
            .find("ASID_SWITCH_ABORT_DETAIL")
            .expect("DETAIL present");
        let around = &PAGE_TABLE_SRC[detail_pos..detail_pos.saturating_add(300)];
        assert!(
            around.contains("missing=") && around.contains("va="),
            "ASID_SWITCH_ABORT_DETAIL must report which mapping is missing and its va"
        );
    }

    // 5. The USER_CR3_RETURN_CTX_MAP_* markers must all exist, in order.
    #[test]
    fn stage141_return_ctx_map_markers_exist() {
        for marker in [
            "USER_CR3_RETURN_CTX_MAP_BEGIN",
            "USER_CR3_RETURN_CTX_MAP_PAGE",
            "USER_CR3_RETURN_CTX_MAP_OK",
        ] {
            assert!(
                PAGE_TABLE_SRC.contains(marker),
                "page_table.rs must emit {marker}"
            );
        }
        let begin_pos = PAGE_TABLE_SRC
            .find("USER_CR3_RETURN_CTX_MAP_BEGIN")
            .expect("BEGIN present");
        let ok_pos = PAGE_TABLE_SRC
            .find("USER_CR3_RETURN_CTX_MAP_OK")
            .expect("OK present");
        assert!(begin_pos < ok_pos, "BEGIN must precede OK in source");
    }

    // 6. The Stage 140 pre-IRET markers must remain present.
    #[test]
    fn stage141_pre_iret_markers_remain() {
        for marker in [
            "USER_CR3_PRE_IRET_CHECK",
            "USER_CR3_PRE_IRET_SWITCH",
            "USER_CR3_PRE_IRET_OK",
        ] {
            assert!(TRAP_RS_SRC.contains(marker), "trap.rs must retain {marker}");
        }
    }

    // 7. PAGE_FAULT_HANDLED_DEMAND must still be gated on the hardware PTE walk.
    #[test]
    fn stage141_handled_demand_still_gated_on_hw_walk() {
        let handled_pos = FAULT_SRC
            .find("PAGE_FAULT_HANDLED_DEMAND")
            .expect("PAGE_FAULT_HANDLED_DEMAND must remain in fault_state.rs");
        let before = &FAULT_SRC[..handled_pos];
        assert!(
            before.contains("hw_demand_ok"),
            "PAGE_FAULT_HANDLED_DEMAND must remain inside an hw_demand_ok gate"
        );
    }

    // 8-9. Syscall ABI must not change.
    #[test]
    fn stage141_syscall_counts_unchanged() {
        assert_eq!(SYSCALL_COUNT, 31, "Stage 141 must not change SYSCALL_COUNT");
        assert_eq!(
            Syscall::VARIANT_COUNT,
            23,
            "Stage 141 must not change Syscall::VARIANT_COUNT"
        );
    }
}

// ── Stage 142 — map the full live kernel stack window before user-return CR3 switch ──
#[cfg(test)]
mod stage142_stack_window_mapping {
    use crate::kernel::syscall::{SYSCALL_COUNT, Syscall};

    const TRAP_RS_SRC: &str = include_str!("../../arch/x86_64/trap.rs");
    const PAGE_TABLE_SRC: &str = include_str!("../../arch/x86_64/page_table.rs");
    const FAULT_SRC: &str = include_str!("fault_state.rs");

    // 1. ensure_kernel_return_context_mapped_for_asid must accept stack_base,
    //    stack_top, and rsp parameters (Stage 143 re-adds rsp alongside the bounds).
    #[test]
    fn stage142_ensure_signature_uses_stack_bounds() {
        let fn_start = PAGE_TABLE_SRC
            .find("fn ensure_kernel_return_context_mapped_for_asid")
            .expect("function must be defined in page_table.rs");
        let fn_body = &PAGE_TABLE_SRC[fn_start..];
        let sig_end = fn_body
            .find("->")
            .expect("function must have a return type");
        let sig = &fn_body[..sig_end];
        assert!(
            sig.contains("stack_base"),
            "signature must include a stack_base parameter"
        );
        assert!(
            sig.contains("stack_top"),
            "signature must include a stack_top parameter"
        );
        // Stage 143 re-introduces rsp: u64 alongside stack_base+stack_top for
        // range verification; all three coexisting is the correct Stage 143 state.
    }

    // 2. ensure_user_return_cr3 in trap.rs must call find_kernel_stack_bounds_containing_rsp
    //    (Stage 143: with_tcbs is now inside that helper, not directly in ensure_user_return_cr3).
    #[test]
    fn stage142_trap_looks_up_tcb_stack_bounds() {
        let fn_start = TRAP_RS_SRC
            .find("fn ensure_user_return_cr3")
            .expect("ensure_user_return_cr3 must be defined in trap.rs");
        let fn_body = &TRAP_RS_SRC[fn_start..];
        assert!(
            fn_body.contains("find_kernel_stack_bounds_containing_rsp"),
            "ensure_user_return_cr3 must call find_kernel_stack_bounds_containing_rsp"
        );
        assert!(
            fn_body.contains("stack_base") && fn_body.contains("stack_top"),
            "ensure_user_return_cr3 must use stack_base and stack_top from the helper"
        );
        // The helper call must appear before ensure_kernel_return_context_mapped_for_asid.
        let helper_pos = fn_body
            .find("find_kernel_stack_bounds_containing_rsp")
            .expect("helper call must be present");
        let map_pos = fn_body
            .find("ensure_kernel_return_context_mapped_for_asid")
            .expect("ensure_kernel_return_context_mapped_for_asid call must be present");
        assert!(
            helper_pos < map_pos,
            "find_kernel_stack_bounds_containing_rsp must precede the mapping call"
        );
    }

    // 3. The mapping function must contain a while-loop over the full stack window.
    #[test]
    fn stage142_stack_loop_covers_full_window() {
        let fn_start = PAGE_TABLE_SRC
            .find("fn ensure_kernel_return_context_mapped_for_asid")
            .expect("function must be defined in page_table.rs");
        let fn_body = &PAGE_TABLE_SRC[fn_start..];
        assert!(
            fn_body.contains("while page_va < stack_top"),
            "function must iterate stack pages with a while loop driven by stack_top"
        );
        assert!(
            fn_body.contains("PAGE_SIZE_U64"),
            "loop must advance page_va by PAGE_SIZE_U64 each iteration"
        );
    }

    // 4. USER_CR3_RETURN_STACK_MAP_BEGIN marker must exist in page_table.rs.
    #[test]
    fn stage142_stack_map_begin_marker() {
        assert!(
            PAGE_TABLE_SRC.contains("USER_CR3_RETURN_STACK_MAP_BEGIN"),
            "page_table.rs must emit USER_CR3_RETURN_STACK_MAP_BEGIN"
        );
        // BEGIN must carry base and top fields.
        let marker_pos = PAGE_TABLE_SRC
            .find("USER_CR3_RETURN_STACK_MAP_BEGIN")
            .expect("marker present");
        let around = &PAGE_TABLE_SRC[marker_pos..marker_pos.saturating_add(200)];
        assert!(
            around.contains("base=") && around.contains("top="),
            "USER_CR3_RETURN_STACK_MAP_BEGIN must report base= and top="
        );
    }

    // 5. USER_CR3_RETURN_STACK_MAP_PAGE marker must exist in page_table.rs.
    #[test]
    fn stage142_stack_map_page_marker() {
        assert!(
            PAGE_TABLE_SRC.contains("USER_CR3_RETURN_STACK_MAP_PAGE"),
            "page_table.rs must emit USER_CR3_RETURN_STACK_MAP_PAGE per stack page"
        );
        // Marker must report va, present, user, writable fields.
        let marker_pos = PAGE_TABLE_SRC
            .find("USER_CR3_RETURN_STACK_MAP_PAGE")
            .expect("marker present");
        let around = &PAGE_TABLE_SRC[marker_pos..marker_pos.saturating_add(200)];
        assert!(
            around.contains("va=") && around.contains("present="),
            "USER_CR3_RETURN_STACK_MAP_PAGE must report va= and present="
        );
    }

    // 6. USER_CR3_RETURN_STACK_MAP_OK marker must exist in page_table.rs and
    //    appear after USER_CR3_RETURN_STACK_MAP_BEGIN.
    #[test]
    fn stage142_stack_map_ok_marker() {
        assert!(
            PAGE_TABLE_SRC.contains("USER_CR3_RETURN_STACK_MAP_OK"),
            "page_table.rs must emit USER_CR3_RETURN_STACK_MAP_OK on success"
        );
        let begin_pos = PAGE_TABLE_SRC
            .find("USER_CR3_RETURN_STACK_MAP_BEGIN")
            .expect("BEGIN present");
        let ok_pos = PAGE_TABLE_SRC
            .find("USER_CR3_RETURN_STACK_MAP_OK")
            .expect("OK present");
        assert!(
            begin_pos < ok_pos,
            "USER_CR3_RETURN_STACK_MAP_BEGIN must precede USER_CR3_RETURN_STACK_MAP_OK"
        );
    }

    // 7. USER_CR3_RETURN_STACK_PROBE marker must exist and report present/user/writable.
    #[test]
    fn stage142_stack_probe_marker_has_present_user_writable() {
        assert!(
            PAGE_TABLE_SRC.contains("USER_CR3_RETURN_STACK_PROBE"),
            "page_table.rs must emit USER_CR3_RETURN_STACK_PROBE to verify each mapped page"
        );
        let marker_pos = PAGE_TABLE_SRC
            .find("USER_CR3_RETURN_STACK_PROBE")
            .expect("marker present");
        let around = &PAGE_TABLE_SRC[marker_pos..marker_pos.saturating_add(200)];
        assert!(
            around.contains("present="),
            "USER_CR3_RETURN_STACK_PROBE must include present= field"
        );
        assert!(
            around.contains("user="),
            "USER_CR3_RETURN_STACK_PROBE must include user= field"
        );
        assert!(
            around.contains("writable="),
            "USER_CR3_RETURN_STACK_PROBE must include writable= field"
        );
    }

    // 8. Stack pages in the window must be mapped with KERNEL_RW (never user-accessible).
    #[test]
    fn stage142_stack_pages_use_kernel_rw_not_user() {
        let fn_start = PAGE_TABLE_SRC
            .find("fn ensure_kernel_return_context_mapped_for_asid")
            .expect("function must be defined in page_table.rs");
        let fn_body = &PAGE_TABLE_SRC[fn_start..];
        assert!(
            fn_body.contains("PageFlags::KERNEL_RW"),
            "stack window mapping must use PageFlags::KERNEL_RW (supervisor-only writable)"
        );
        // The loop section from STACK_MAP_BEGIN to STACK_MAP_OK must not use USER flags.
        let begin_pos = fn_body
            .find("USER_CR3_RETURN_STACK_MAP_BEGIN")
            .expect("STACK_MAP_BEGIN present");
        let ok_pos = fn_body
            .find("USER_CR3_RETURN_STACK_MAP_OK")
            .expect("STACK_MAP_OK present");
        let loop_section = &fn_body[begin_pos..ok_pos];
        assert!(
            !loop_section.contains("user: true"),
            "stack window mapping must never use user: true"
        );
    }

    // 9. Stage 140/141 diagnostic markers must remain present.
    #[test]
    fn stage142_stage141_stage140_markers_remain() {
        for marker in [
            "USER_CR3_PRE_IRET_CHECK",
            "USER_CR3_PRE_IRET_SWITCH",
            "USER_CR3_PRE_IRET_OK",
        ] {
            assert!(TRAP_RS_SRC.contains(marker), "trap.rs must retain {marker}");
        }
        for marker in [
            "USER_CR3_RETURN_CTX_MAP_BEGIN",
            "USER_CR3_RETURN_CTX_MAP_OK",
            "ASID_SWITCH_ABORT_DETAIL",
        ] {
            assert!(
                PAGE_TABLE_SRC.contains(marker),
                "page_table.rs must retain {marker}"
            );
        }
        // Stage 138: hardware fault diagnostics must remain.
        assert!(
            FAULT_SRC.contains("PAGE_FAULT_HANDLED_DEMAND"),
            "fault_state.rs must retain PAGE_FAULT_HANDLED_DEMAND"
        );
    }

    // 10. Syscall ABI must not change.
    #[test]
    fn stage142_syscall_counts_unchanged() {
        assert_eq!(SYSCALL_COUNT, 31, "Stage 142 must not change SYSCALL_COUNT");
        assert_eq!(
            Syscall::VARIANT_COUNT,
            23,
            "Stage 142 must not change Syscall::VARIANT_COUNT"
        );
    }
}

// ── Stage 143 — map live kernel stack containing sampled RSP, not target TCB stack ──
#[cfg(test)]
mod stage143_live_stack_selection {
    use crate::kernel::syscall::{SYSCALL_COUNT, Syscall};

    const TRAP_RS_SRC: &str = include_str!("../../arch/x86_64/trap.rs");
    const PAGE_TABLE_SRC: &str = include_str!("../../arch/x86_64/page_table.rs");
    const FAULT_SRC: &str = include_str!("fault_state.rs");

    // 1. ensure_user_return_cr3 must pass rsp to ensure_kernel_return_context_mapped_for_asid.
    #[test]
    fn stage143_ensure_user_return_cr3_passes_rsp_to_helper() {
        let fn_start = TRAP_RS_SRC
            .find("fn ensure_user_return_cr3")
            .expect("ensure_user_return_cr3 must be defined in trap.rs");
        let fn_body = &TRAP_RS_SRC[fn_start..];
        let call_pos = fn_body
            .find("ensure_kernel_return_context_mapped_for_asid")
            .expect("mapping helper call must be present");
        // Grab enough text after the call site to see the argument list.
        let call_site = &fn_body[call_pos..call_pos.saturating_add(300)];
        assert!(
            call_site.contains("rsp"),
            "call to ensure_kernel_return_context_mapped_for_asid must include rsp argument"
        );
    }

    // 2. find_kernel_stack_bounds_containing_rsp must scan all TCBs for rsp in range.
    #[test]
    fn stage143_stack_selection_finds_stack_containing_rsp() {
        assert!(
            TRAP_RS_SRC.contains("fn find_kernel_stack_bounds_containing_rsp"),
            "trap.rs must define find_kernel_stack_bounds_containing_rsp"
        );
        let fn_start = TRAP_RS_SRC
            .find("fn find_kernel_stack_bounds_containing_rsp")
            .expect("function present");
        let fn_body = &TRAP_RS_SRC[fn_start..fn_start.saturating_add(800)];
        assert!(
            fn_body.contains("with_tcbs"),
            "find_kernel_stack_bounds_containing_rsp must use with_tcbs to scan all TCBs"
        );
        assert!(
            fn_body.contains("rsp >= base") || fn_body.contains("base <= rsp"),
            "helper must check rsp >= base"
        );
        assert!(
            fn_body.contains("rsp < top") || fn_body.contains("top > rsp"),
            "helper must check rsp < top"
        );
    }

    // 3. ensure_kernel_return_context_mapped_for_asid must fail with reason=rsp_not_in_range
    //    when the selected stack window does not contain sampled RSP.
    #[test]
    fn stage143_helper_refuses_ok_if_rsp_outside_range() {
        assert!(
            PAGE_TABLE_SRC.contains("reason=rsp_not_in_range"),
            "page_table.rs must emit USER_CR3_RETURN_STACK_MAP_FAILED reason=rsp_not_in_range"
        );
        // The range check must appear before the stack-map loop (before STACK_MAP_BEGIN).
        let check_pos = PAGE_TABLE_SRC
            .find("rsp_not_in_range")
            .expect("rsp_not_in_range present");
        let begin_pos = PAGE_TABLE_SRC
            .find("USER_CR3_RETURN_STACK_MAP_BEGIN")
            .expect("STACK_MAP_BEGIN present");
        assert!(
            check_pos < begin_pos,
            "rsp range check must appear before STACK_MAP_BEGIN loop"
        );
    }

    // 4. The RSP page must be a hard failure when absent from the live root.
    #[test]
    fn stage143_helper_refuses_ok_if_rsp_page_not_mapped() {
        assert!(
            PAGE_TABLE_SRC.contains("rsp_page_absent_from_live"),
            "page_table.rs must fail with reason=rsp_page_absent_from_live when RSP page missing from live root"
        );
        assert!(
            PAGE_TABLE_SRC.contains("rsp_page_not_in_target"),
            "page_table.rs must fail with reason=rsp_page_not_in_target when RSP page absent from target after mapping"
        );
    }

    // 5. USER_CR3_RETURN_STACK_SELECT marker must appear in trap.rs with all required fields.
    #[test]
    fn stage143_stack_select_marker_exists() {
        assert!(
            TRAP_RS_SRC.contains("USER_CR3_RETURN_STACK_SELECT"),
            "trap.rs must emit USER_CR3_RETURN_STACK_SELECT"
        );
        let pos = TRAP_RS_SRC
            .find("USER_CR3_RETURN_STACK_SELECT")
            .expect("marker present");
        let around = &TRAP_RS_SRC[pos..pos.saturating_add(300)];
        assert!(
            around.contains("rsp="),
            "USER_CR3_RETURN_STACK_SELECT must include rsp="
        );
        assert!(
            around.contains("base="),
            "USER_CR3_RETURN_STACK_SELECT must include base="
        );
        assert!(
            around.contains("top="),
            "USER_CR3_RETURN_STACK_SELECT must include top="
        );
        assert!(
            around.contains("owner_tid="),
            "USER_CR3_RETURN_STACK_SELECT must include owner_tid="
        );
    }

    // 6. USER_CR3_RETURN_STACK_MAP_FAILED must include a reason= field in page_table.rs.
    #[test]
    fn stage143_stack_map_failed_marker_with_reason() {
        assert!(
            PAGE_TABLE_SRC.contains("USER_CR3_RETURN_STACK_MAP_FAILED"),
            "page_table.rs must emit USER_CR3_RETURN_STACK_MAP_FAILED"
        );
        let pos = PAGE_TABLE_SRC
            .find("USER_CR3_RETURN_STACK_MAP_FAILED")
            .expect("marker present");
        let around = &PAGE_TABLE_SRC[pos..pos.saturating_add(200)];
        assert!(
            around.contains("reason="),
            "USER_CR3_RETURN_STACK_MAP_FAILED must include reason= field"
        );
    }

    // 7. USER_CR3_RETURN_STACK_MAP_OK must be emitted only inside an `if stack_all_ok` block.
    #[test]
    fn stage143_stack_map_ok_gated_on_verification() {
        let fn_start = PAGE_TABLE_SRC
            .find("fn ensure_kernel_return_context_mapped_for_asid")
            .expect("function must be defined in page_table.rs");
        let fn_body = &PAGE_TABLE_SRC[fn_start..];
        let gate_pos = fn_body
            .find("if stack_all_ok")
            .expect("if stack_all_ok gate must exist in the function");
        let ok_pos = fn_body
            .find("USER_CR3_RETURN_STACK_MAP_OK")
            .expect("USER_CR3_RETURN_STACK_MAP_OK must exist");
        assert!(
            gate_pos < ok_pos,
            "USER_CR3_RETURN_STACK_MAP_OK must appear after the `if stack_all_ok` gate"
        );
    }

    // 8. write_cr3_for_asid must remain gated behind ctx_mapped in trap.rs.
    #[test]
    fn stage143_write_cr3_gated_behind_ctx_mapped() {
        let fn_start = TRAP_RS_SRC
            .find("fn ensure_user_return_cr3")
            .expect("ensure_user_return_cr3 must be defined in trap.rs");
        let fn_body = &TRAP_RS_SRC[fn_start..];
        let gate_pos = fn_body
            .find("if ctx_mapped")
            .expect("if ctx_mapped gate must exist");
        let write_pos = fn_body
            .find("write_cr3_for_asid")
            .expect("write_cr3_for_asid must be called");
        assert!(
            gate_pos < write_pos,
            "write_cr3_for_asid must appear after the `if ctx_mapped` gate"
        );
    }

    // 9. PAGE_FAULT_HANDLED_DEMAND in fault_state.rs must remain gated on hw_demand_ok.
    #[test]
    fn stage143_handled_demand_still_gated_on_hw_walk() {
        assert!(
            FAULT_SRC.contains("PAGE_FAULT_HANDLED_DEMAND"),
            "fault_state.rs must retain PAGE_FAULT_HANDLED_DEMAND"
        );
        assert!(
            FAULT_SRC.contains("hw_demand_ok"),
            "fault_state.rs must retain hw_demand_ok guard for PAGE_FAULT_HANDLED_DEMAND"
        );
        let gate_pos = FAULT_SRC
            .find("hw_demand_ok")
            .expect("hw_demand_ok guard present");
        let handled_pos = FAULT_SRC
            .find("PAGE_FAULT_HANDLED_DEMAND")
            .expect("marker present");
        assert!(
            gate_pos < handled_pos,
            "hw_demand_ok guard must precede PAGE_FAULT_HANDLED_DEMAND"
        );
    }

    // 10. Syscall count must not change.
    #[test]
    fn stage143_syscall_count() {
        assert_eq!(SYSCALL_COUNT, 31, "Stage 143 must not change SYSCALL_COUNT");
    }

    // 11. Syscall variant count must not change.
    #[test]
    fn stage143_syscall_variant_count() {
        assert_eq!(
            Syscall::VARIANT_COUNT,
            23,
            "Stage 143 must not change Syscall::VARIANT_COUNT"
        );
    }
}

// ── Stage 144 — gate x86_64-only trampoline symbol; arch-safe kernel_switch_frame_trampoline_ip ──
#[cfg(test)]
mod stage144_arch_safe_trampoline_ip {
    use crate::kernel::syscall::{SYSCALL_COUNT, Syscall};

    const THREAD_STATE_SRC: &str = include_str!("thread_state.rs");
    const TRAP_ENTRY_SRC: &str = include_str!("../../arch/trap_entry.rs");

    // 1. Direct references to yarm_kernel_thread_switch_trampoline (without _rust or _bridge
    //    suffix) must only appear inside x86_64-cfg-gated blocks in thread_state.rs.
    #[test]
    fn stage144_trampoline_symbol_refs_are_x86_64_only() {
        // The extern "C" declaration is gated.
        let extern_pos = THREAD_STATE_SRC
            .find("unsafe extern \"C\"")
            .expect("extern block must exist");
        let cfg_before = THREAD_STATE_SRC[..extern_pos]
            .rfind("target_arch = \"x86_64\"")
            .expect("extern block must be preceded by x86_64 cfg");
        assert!(
            THREAD_STATE_SRC[cfg_before..extern_pos].len() < 200,
            "x86_64 cfg must be close to the extern block"
        );
        // The raw symbol cast must live inside the x86_64 arm of kernel_switch_frame_trampoline_ip.
        let cast_pos = THREAD_STATE_SRC
            .find("yarm_kernel_thread_switch_trampoline as *const () as usize")
            .expect("raw cast must still exist in x86_64 arm");
        let cfg_before_cast = THREAD_STATE_SRC[..cast_pos]
            .rfind("target_arch = \"x86_64\"")
            .expect("raw cast must be guarded by x86_64 cfg");
        assert!(
            THREAD_STATE_SRC[cfg_before_cast..cast_pos].len() < 200,
            "x86_64 cfg must be close to the raw cast"
        );
    }

    // 2. Common initialization must use kernel_switch_frame_trampoline_ip(), not the raw symbol.
    #[test]
    fn stage144_provision_uses_trampoline_ip_helper() {
        let fn_start = THREAD_STATE_SRC
            .find("fn provision_default_kernel_context")
            .expect("provision_default_kernel_context must exist");
        // The function spans ~50 lines; search from its start to the next `pub(crate) fn`.
        let fn_end = THREAD_STATE_SRC[fn_start..]
            .find("\n    pub(crate) fn release_kernel_context")
            .map(|rel| fn_start + rel)
            .unwrap_or(THREAD_STATE_SRC.len());
        let fn_body = &THREAD_STATE_SRC[fn_start..fn_end];
        assert!(
            fn_body.contains("kernel_switch_frame_trampoline_ip()"),
            "provision_default_kernel_context must call kernel_switch_frame_trampoline_ip()"
        );
        assert!(
            !fn_body.contains("yarm_kernel_thread_switch_trampoline as *const"),
            "provision_default_kernel_context must not reference the raw asm symbol directly"
        );
    }

    // 3. kernel_switch_frame_trampoline_ip must have a non-x86_64 fallback path.
    #[test]
    fn stage144_trampoline_ip_has_non_x86_fallback() {
        let fn_start = THREAD_STATE_SRC
            .find("fn kernel_switch_frame_trampoline_ip()")
            .expect("function must be defined");
        let fn_body = &THREAD_STATE_SRC[fn_start..fn_start.saturating_add(400)];
        assert!(
            fn_body.contains("not(target_arch = \"x86_64\")"),
            "kernel_switch_frame_trampoline_ip must have a non-x86_64 cfg arm"
        );
        assert!(
            fn_body.contains("yarm_kernel_thread_switch_trampoline_rust_real"),
            "non-x86_64 arm must return the Rust real handler address"
        );
    }

    // 4. trap_entry.rs references to the raw shim must remain x86_64-gated.
    #[test]
    fn stage144_trap_entry_trampoline_ref_is_x86_64_gated() {
        let raw_ref_pos = TRAP_ENTRY_SRC
            .find("yarm_kernel_thread_switch_trampoline")
            .expect("trap_entry.rs must reference the trampoline for the stash check");
        let cfg_before = TRAP_ENTRY_SRC[..raw_ref_pos]
            .rfind("target_arch = \"x86_64\"")
            .expect("trap_entry.rs trampoline reference must be inside x86_64 cfg block");
        assert!(
            TRAP_ENTRY_SRC[cfg_before..raw_ref_pos].len() < 300,
            "x86_64 cfg must precede the trampoline reference in trap_entry.rs"
        );
    }

    // 5. D6 proof must remain x86_64/default-off.
    #[test]
    fn stage144_d6_proof_remains_default_off() {
        let boot_cmdline = include_str!("../boot_command_line.rs");
        assert!(
            boot_cmdline.contains("d6_switch_proof: Option<bool>"),
            "D6 proof knob must remain Option<bool> (default-off)"
        );
    }

    // 6. SYSCALL_COUNT unchanged.
    #[test]
    fn stage144_syscall_count() {
        assert_eq!(SYSCALL_COUNT, 31, "Stage 144 must not change SYSCALL_COUNT");
    }

    // 7. Syscall::VARIANT_COUNT unchanged.
    #[test]
    fn stage144_syscall_variant_count() {
        assert_eq!(
            Syscall::VARIANT_COUNT,
            23,
            "Stage 144 must not change Syscall::VARIANT_COUNT"
        );
    }
}

mod stage145_vm_module_extraction {
    use crate::kernel::syscall::{SYSCALL_COUNT, Syscall};

    const SYSCALL_SRC: &str = include_str!("../syscall.rs");
    const VM_SRC: &str = include_str!("../syscall/vm.rs");

    // 1. vm.rs must exist and declare the three pub(super) handlers.
    #[test]
    fn stage145_vm_module_has_three_handlers() {
        assert!(
            VM_SRC.contains("pub(super) fn handle_vm_map("),
            "vm.rs must contain handle_vm_map"
        );
        assert!(
            VM_SRC.contains("pub(super) fn handle_vm_anon_map("),
            "vm.rs must contain handle_vm_anon_map"
        );
        assert!(
            VM_SRC.contains("pub(super) fn handle_vm_brk("),
            "vm.rs must contain handle_vm_brk"
        );
    }

    // 2. vm_map_page_flags, validate_anon_map_args, rollback_anon_map must live in vm.rs only.
    #[test]
    fn stage145_vm_helpers_live_in_vm_module() {
        assert!(
            VM_SRC.contains("fn vm_map_page_flags("),
            "vm.rs must contain vm_map_page_flags"
        );
        assert!(
            VM_SRC.contains("fn validate_anon_map_args("),
            "vm.rs must contain validate_anon_map_args"
        );
        assert!(
            VM_SRC.contains("fn rollback_anon_map("),
            "vm.rs must contain rollback_anon_map"
        );
        // These private helpers must not remain in the parent syscall.rs.
        assert!(
            !SYSCALL_SRC.contains("fn vm_map_page_flags("),
            "syscall.rs must NOT contain vm_map_page_flags (moved to vm.rs)"
        );
        assert!(
            !SYSCALL_SRC.contains("fn validate_anon_map_args("),
            "syscall.rs must NOT contain validate_anon_map_args (moved to vm.rs)"
        );
        assert!(
            !SYSCALL_SRC.contains("fn rollback_anon_map("),
            "syscall.rs must NOT contain rollback_anon_map (moved to vm.rs)"
        );
    }

    // 3. syscall.rs must declare `mod vm;` inside the decomposition block.
    #[test]
    fn stage145_syscall_declares_vm_module() {
        assert!(
            SYSCALL_SRC.contains("mod vm;"),
            "syscall.rs must declare `mod vm;`"
        );
    }

    // 4. syscall.rs dispatch arms must delegate via self::vm::.
    #[test]
    fn stage145_dispatch_delegates_to_vm_module() {
        assert!(
            SYSCALL_SRC.contains("self::vm::handle_vm_map("),
            "syscall.rs must delegate VmMap to self::vm::handle_vm_map"
        );
        assert!(
            SYSCALL_SRC.contains("self::vm::handle_vm_anon_map("),
            "syscall.rs must delegate VmAnonMap to self::vm::handle_vm_anon_map"
        );
        assert!(
            SYSCALL_SRC.contains("self::vm::handle_vm_brk("),
            "syscall.rs must delegate VmBrk to self::vm::handle_vm_brk"
        );
    }

    // 5. round_up_page and validate_user_region must be accessible from syscall.rs
    //    (Stage 149 moved the bodies to helpers.rs but keeps pub(crate) re-exports here).
    #[test]
    fn stage145_shared_helpers_remain_in_syscall_rs() {
        // Function bodies moved to helpers.rs in Stage 149; re-exported as pub(crate).
        assert!(
            SYSCALL_SRC.contains("round_up_page"),
            "round_up_page must be accessible from syscall.rs namespace"
        );
        assert!(
            SYSCALL_SRC.contains("validate_user_region"),
            "validate_user_region must be accessible from syscall.rs namespace"
        );
    }

    // 6. vm.rs must import round_up_page and validate_user_region from super (syscall.rs).
    #[test]
    fn stage145_vm_imports_helpers_from_super() {
        assert!(
            VM_SRC.contains("round_up_page") && VM_SRC.contains("super::"),
            "vm.rs must import round_up_page from super"
        );
        assert!(
            VM_SRC.contains("validate_user_region") && VM_SRC.contains("super::"),
            "vm.rs must import validate_user_region from super"
        );
    }

    // 7. VM syscall numbers unchanged.
    #[test]
    fn stage145_vm_syscall_numbers_unchanged() {
        use crate::kernel::syscall::{
            SYSCALL_VM_ANON_MAP_NR, SYSCALL_VM_BRK_NR, SYSCALL_VM_MAP_NR,
        };
        assert_eq!(SYSCALL_VM_MAP_NR, 3);
        assert_eq!(SYSCALL_VM_ANON_MAP_NR, 13);
        assert_eq!(SYSCALL_VM_BRK_NR, 14);
    }

    // 8. SYSCALL_COUNT unchanged.
    #[test]
    fn stage145_syscall_count() {
        assert_eq!(SYSCALL_COUNT, 31, "Stage 145 must not change SYSCALL_COUNT");
    }

    // 9. Syscall::VARIANT_COUNT unchanged.
    #[test]
    fn stage145_syscall_variant_count() {
        assert_eq!(
            Syscall::VARIANT_COUNT,
            23,
            "Stage 145 must not change Syscall::VARIANT_COUNT"
        );
    }

    // 10. vm.rs must not contain any inline dispatch (must not call kernel.dispatch or match syscall).
    #[test]
    fn stage145_vm_module_has_no_dispatch_logic() {
        assert!(
            !VM_SRC.contains("fn dispatch("),
            "vm.rs must not contain a dispatch function"
        );
        assert!(
            !VM_SRC.contains("Syscall::decode("),
            "vm.rs must not decode syscall numbers"
        );
    }

    // 11. VM prot constants remain in syscall.rs (ABI-stable, used by userspace contracts).
    #[test]
    fn stage145_prot_constants_remain_in_syscall_rs() {
        assert!(
            SYSCALL_SRC.contains("pub const SYSCALL_VM_MAP_PROT_READ"),
            "SYSCALL_VM_MAP_PROT_READ must remain in syscall.rs"
        );
        assert!(
            SYSCALL_SRC.contains("pub const SYSCALL_VM_MAP_PROT_WRITE"),
            "SYSCALL_VM_MAP_PROT_WRITE must remain in syscall.rs"
        );
        assert!(
            SYSCALL_SRC.contains("pub const SYSCALL_VM_MAP_PROT_EXEC"),
            "SYSCALL_VM_MAP_PROT_EXEC must remain in syscall.rs"
        );
    }
}

mod stage146_ipc_module_extraction {
    use crate::kernel::syscall::{SYSCALL_COUNT, Syscall};

    const SYSCALL_SRC: &str = include_str!("../syscall.rs");
    const IPC_SRC: &str = include_str!("../syscall/ipc.rs");

    // 1. ipc.rs must declare the five pub(super) handler functions.
    #[test]
    fn stage146_ipc_module_has_five_handlers() {
        assert!(
            IPC_SRC.contains("pub(super) fn handle_ipc_send("),
            "ipc.rs must contain pub(super) fn handle_ipc_send"
        );
        assert!(
            IPC_SRC.contains("pub(super) fn handle_ipc_recv("),
            "ipc.rs must contain pub(super) fn handle_ipc_recv"
        );
        assert!(
            IPC_SRC.contains("pub(super) fn handle_ipc_recv_timeout("),
            "ipc.rs must contain pub(super) fn handle_ipc_recv_timeout"
        );
        assert!(
            IPC_SRC.contains("pub(super) fn handle_ipc_call("),
            "ipc.rs must contain pub(super) fn handle_ipc_call"
        );
        assert!(
            IPC_SRC.contains("pub(super) fn handle_ipc_reply("),
            "ipc.rs must contain pub(super) fn handle_ipc_reply"
        );
    }

    // 2. Private IPC helpers must live in ipc.rs and not in syscall.rs.
    #[test]
    fn stage146_ipc_helpers_live_in_ipc_module() {
        for helper in &[
            "fn transfer_flag_bits(",
            "fn validate_transfer_cap(",
            "fn validate_shared_mem_transfer_rights(",
            "fn stash_transfer_handle(",
            "fn inline_payload_from_frame(",
            "fn map_shared_region_into_receiver(",
            "fn revoke_current_transfer_cap_best_effort(",
            "fn attenuate_transfer_cap_for_recv_intent(",
            "fn recv_shared_mem_map_intent_flags(",
            "fn handle_ipc_recv_result(",
            "fn handle_ipc_recv_result_with_empty_error(",
        ] {
            assert!(IPC_SRC.contains(helper), "ipc.rs must contain {helper}");
            assert!(
                !SYSCALL_SRC.contains(helper),
                "syscall.rs must NOT contain {helper} (moved to ipc.rs)"
            );
        }
    }

    // 3. syscall.rs must declare `mod ipc;` in the decomposition block.
    #[test]
    fn stage146_syscall_declares_ipc_module() {
        assert!(
            SYSCALL_SRC.contains("mod ipc;"),
            "syscall.rs must declare `mod ipc;`"
        );
    }

    // 4. syscall.rs must have thin shims delegating to self::ipc::.
    #[test]
    fn stage146_dispatch_delegates_to_ipc_module() {
        assert!(
            SYSCALL_SRC.contains("self::ipc::handle_ipc_send("),
            "syscall.rs must delegate IpcSend to self::ipc::handle_ipc_send"
        );
        assert!(
            SYSCALL_SRC.contains("self::ipc::handle_ipc_recv("),
            "syscall.rs must delegate IpcRecv to self::ipc::handle_ipc_recv"
        );
        assert!(
            SYSCALL_SRC.contains("self::ipc::handle_ipc_recv_timeout("),
            "syscall.rs must delegate IpcRecvTimeout to self::ipc::handle_ipc_recv_timeout"
        );
        assert!(
            SYSCALL_SRC.contains("self::ipc::handle_ipc_call("),
            "syscall.rs must delegate IpcCall to self::ipc::handle_ipc_call"
        );
        assert!(
            SYSCALL_SRC.contains("self::ipc::handle_ipc_reply("),
            "syscall.rs must delegate IpcReply to self::ipc::handle_ipc_reply"
        );
    }

    // 5. [I] helpers that must stay in syscall.rs post-Stage-150.
    //    Note: encode_transfer_cap_ret, should_strip_inline_opcode_prefix,
    //    sender_tid_to_ret moved to ipc_abi.rs in Stage 150 and re-imported here.
    #[test]
    fn stage146_shared_helpers_remain_in_syscall_rs() {
        assert!(
            SYSCALL_SRC.contains("pub(super) fn try_endpoint_split_recv("),
            "try_endpoint_split_recv must remain pub(super) in syscall.rs"
        );
        assert!(
            SYSCALL_SRC.contains("pub(super) fn clear_blocked_recv_state("),
            "clear_blocked_recv_state must remain pub(super) in syscall.rs"
        );
        // encode_transfer_cap_ret, should_strip_inline_opcode_prefix, sender_tid_to_ret
        // moved to ipc_abi.rs in Stage 150; accessible via private re-import.
        assert!(
            SYSCALL_SRC.contains("use self::ipc_abi::{"),
            "ipc_abi functions must be re-imported in syscall.rs"
        );
        assert!(
            SYSCALL_SRC.contains("encode_transfer_cap_ret"),
            "encode_transfer_cap_ret must be accessible from syscall.rs namespace"
        );
        assert!(
            SYSCALL_SRC.contains("sender_tid_to_ret"),
            "sender_tid_to_ret must be accessible from syscall.rs namespace"
        );
    }

    // 6. ipc.rs imports shared helpers from super (not duplicating them).
    #[test]
    fn stage146_ipc_imports_helpers_from_super() {
        assert!(
            IPC_SRC.contains("super::") && IPC_SRC.contains("try_endpoint_split_recv"),
            "ipc.rs must import try_endpoint_split_recv from super"
        );
        assert!(
            IPC_SRC.contains("super::") && IPC_SRC.contains("encode_transfer_cap_ret"),
            "ipc.rs must import encode_transfer_cap_ret from super"
        );
        assert!(
            IPC_SRC.contains("super::") && IPC_SRC.contains("should_strip_inline_opcode_prefix"),
            "ipc.rs must import should_strip_inline_opcode_prefix from super"
        );
    }

    // 7. IPC syscall numbers unchanged.
    #[test]
    fn stage146_ipc_syscall_numbers_unchanged() {
        use crate::kernel::syscall::{
            SYSCALL_IPC_CALL_NR, SYSCALL_IPC_RECV_NR, SYSCALL_IPC_RECV_TIMEOUT_NR,
            SYSCALL_IPC_REPLY_NR, SYSCALL_IPC_SEND_NR,
        };
        assert_eq!(SYSCALL_IPC_SEND_NR, 1);
        assert_eq!(SYSCALL_IPC_RECV_NR, 2);
        assert_eq!(SYSCALL_IPC_RECV_TIMEOUT_NR, 5);
        assert_eq!(SYSCALL_IPC_CALL_NR, 6);
        assert_eq!(SYSCALL_IPC_REPLY_NR, 7);
    }

    // 8. SYSCALL_COUNT unchanged.
    #[test]
    fn stage146_syscall_count() {
        assert_eq!(SYSCALL_COUNT, 31, "Stage 146 must not change SYSCALL_COUNT");
    }

    // 9. Syscall::VARIANT_COUNT unchanged.
    #[test]
    fn stage146_syscall_variant_count() {
        assert_eq!(
            Syscall::VARIANT_COUNT,
            23,
            "Stage 146 must not change Syscall::VARIANT_COUNT"
        );
    }

    // 10. ipc.rs must not contain inline dispatch logic.
    #[test]
    fn stage146_ipc_module_has_no_dispatch_logic() {
        assert!(
            !IPC_SRC.contains("fn dispatch("),
            "ipc.rs must not contain a dispatch function"
        );
        assert!(
            !IPC_SRC.contains("Syscall::decode("),
            "ipc.rs must not decode syscall numbers"
        );
    }

    // 11. syscall.rs dispatch fn must own all five IpcSend/Recv/Call/Reply arms.
    #[test]
    fn stage146_syscall_rs_owns_dispatch() {
        assert!(
            SYSCALL_SRC.contains("Syscall::IpcSend"),
            "syscall.rs dispatch must handle IpcSend"
        );
        assert!(
            SYSCALL_SRC.contains("Syscall::IpcRecv"),
            "syscall.rs dispatch must handle IpcRecv"
        );
        assert!(
            SYSCALL_SRC.contains("Syscall::IpcCall"),
            "syscall.rs dispatch must handle IpcCall"
        );
        assert!(
            SYSCALL_SRC.contains("Syscall::IpcReply"),
            "syscall.rs dispatch must handle IpcReply"
        );
    }
}

